322→func buildBanner(s *sessionStatus) string {
323→	var b strings.Builder
324→	ver := fmt.Sprintf("nurge %s", buildVersion)
325→
326→	// Line 1: Powered by Nurge
327→	b.WriteString("\n\nPowered by Nurge\n")
328→	// Line 2: Version
329→	fmt.Fprintf(&b, "  %s\n", ver)
330→
331→	if !s.configLoaded {
332→		b.WriteString("  Run: nurge to get started")
333→		return b.String()
334→	}
335→
336→	// --- Pre-setup: no connectors yet ---
337→	hasConnectors := false
338→	for _, c := range s.connectors {
339→		if c.Connected {
340→			hasConnectors = true
341→			break
342→		}
343→	}
344→	if !hasConnectors {
345→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
346→		return b.String()
347→	}
348→
349→	// --- Setup in progress ---
350→	if !s.setupCompleted {
351→		name := s.settings["user.name"]
352→		if name != "" {
353→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
354→		} else {
355→			b.WriteString("  Setup in progress.\n")
356→		}
357→		b.WriteString("  Run /nurge:setup to continue where you left off.")
358→		return b.String()
359→	}
360→
361→	// --- Post-setup: compact rotating dashboard ---
362→	name := s.settings["user.name"]
363→	if name != "" {
364→		fmt.Fprintf(&b, "  Hey %s\n", name)
365→	}
366→
367→	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
368→		fmt.Fprintf(&b, "  %s\n", syncLine)
369→	}
370→
371→	// Always show: KPI progress (the one thing that matters most)
372→	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
373→		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
374→		if s.weeklyStats.UniqueContacts > 0 {
375→			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
376→		}
377→		kpiTarget := s.settings["kpi.daily_emails"]
378→		if kpiTarget != "" {
379→			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
380→		}
381→		b.WriteString("\n")
382→	} else {
383→		goal := s.settings["kpi.goal"]
384→		if goal != "" {
385→			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
386→		}
387→	}
388→
389→	// Rotate one additional insight based on day-of-year
390→	// This keeps the banner fresh without overwhelming
391→	slot := time.Now().YearDay() % 5
392→	switch slot {
393→	case 0: // Sending health
394→		warmup := s.settings["sending.warmup_status"]
395→		domainType := s.settings["sending.domain_type"]
396→		if warmup == "fresh" {
397→			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
398→		} else if domainType == "primary" {
399→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
400→		} else {
401→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
402→		}
403→	case 1: // Data snapshot
404→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
405→		if s.outboundTotal > 0 {
406→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
407→		}
408→		if s.contactCount > 0 {
409→			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
410→		}
411→		b.WriteString("\n")
412→	case 2: // Learnings
413→		if s.learningCount > 0 {
414→			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
415→		} else {
416→			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
417→		}
418→	case 3: // Connected services
419→		var connList []string
420→		for id, c := range s.connectors {
421→			if c.Connected {
422→				connList = append(connList, capitalize(id))
423→			}
424→		}
425→		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
426→	case 4: // Quick action suggestion
427→		actions := []string{
428→			"\"research [company]\" — deep-dive a prospect",
429→			"\"write an email to [persona] at [company]\"",
430→			"\"/nurge:review\" — check your KPI progress",
431→			"\"show my pipeline\" — see what needs attention",
432→		}
433→		pick := time.Now().YearDay() / 5 % len(actions)
434→		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
435→	}
436→
437→	return b.String()
438→}
