 72→// runInit is the shared init logic used by both the root command and the hidden init alias.
 73→func runInit(cmd *cobra.Command, args []string) error {
 74→	dirCreated := ""
 75→
 76→	if len(args) == 1 {
 77→		dir := args[0]
 78→		if err := os.MkdirAll(dir, 0755); err != nil {
 79→			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 80→		}
 81→		abs, err := filepath.Abs(dir)
 82→		if err != nil {
 83→			return err
 84→		}
 85→		if err := os.Chdir(abs); err != nil {
 86→			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 87→		}
 88→		dirCreated = dir
 89→	} else if !initForce {
 90→		// No directory arg: only init if current dir is empty or already initialized
 91→		empty, _ := project.IsDirEmpty(".")
 92→		alreadyInit := project.IsNurgeProject(".")
 93→		if !empty && !alreadyInit {
 94→			return cmd.Help()
 95→		}
 96→	}
 97→
 98→	// Check if current directory is non-empty (unless --force)
 99→	if !initForce {
100→		empty, err := project.IsDirEmpty(".")
101→		if err != nil {
102→			return err
103→		}
104→		if !empty && !project.IsNurgeProject(".") {
105→			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
106→		}
107→	}
108→
109→	opts := project.Options{
110→		SkipHooks: initSkipHooks,
111→		Force:     initForce,
112→		Verbose:   initVerbose,
113→	}
114→	if err := project.Run(opts); err != nil {
115→		return err
116→	}
117→
118→	if dirCreated != "" {
119→		fmt.Println()
120→		fmt.Printf("  Now run: cd %s\n", dirCreated)
121→		fmt.Println()
122→	}
123→
124→	return nil
125→}
