178→// runSessionStart outputs JSON with systemMessage (visible banner) and
179→// additionalContext (LLM context) for the SessionStart hook.
180→// Also captures the session in DB + log.
181→func runSessionStart() error {
182→	// Read stdin (Claude Code sends session info)
183→	input, _ := session.ReadStdin()
184→
185→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
186→	if input != nil && input.SessionID != "" && db.Exists() {
187→		if d, err := db.Open(); err == nil {
188→			db.EnsureSessionTables(d)
189→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
190→			session.AddEvent(d, input.SessionID, "session_start", input)
191→			d.Close()
192→		}
193→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
194→		session.FlushLog()
195→	}
196→
197→	// Sync permissions — ensures existing users get any new permissions
198→	// added in later versions. Graceful — never fails the hook.
199→	project.SyncPermissions()
200→
201→	syncReport := attemptSessionStartSync()
202→
203→	// Auto-update check (non-blocking, cached)
204→	updateMsg := checkAndAutoUpdate()
205→
206→	s := gatherStatus()
207→	s.startSync = syncReport
208→
209→	if input != nil && input.SessionID != "" && db.Exists() && syncReport != nil && syncReport.Attempted {
210→		if d, err := db.Open(); err == nil {
211→			db.EnsureSessionTables(d)
212→			session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
213→			d.Close()
214→		}
215→	}
216→
217→	banner := buildBanner(s)
218→	if updateMsg != "" {
219→		banner += "\n  " + updateMsg
220→	}
221→	context := buildPromptContext(s)
222→
223→	out := hookOutput{
224→		SystemMessage: banner,
225→		HookSpecificOut: &hookSpecificOut{
226→			HookEventName:     "SessionStart",
227→			AdditionalContext: context,
228→		},
229→	}
230→
231→	enc := json.NewEncoder(os.Stdout)
232→	return enc.Encode(out)
233→}
