260→// runStop captures a stop event and creates a checkpoint.
261→func runStop() error {
262→	input, err := session.ReadStdin()
263→	if err != nil || input == nil || input.SessionID == "" {
264→		return nil
265→	}
266→
267→	if !db.Exists() {
268→		return nil
269→	}
270→	d, err := db.Open()
271→	if err != nil {
272→		return nil
273→	}
274→	defer d.Close()
275→
276→	db.EnsureSessionTables(d)
277→	session.AddEvent(d, input.SessionID, "stop", input)
278→	if len(input.ModifiedFiles) > 0 {
279→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
280→	}
281→
282→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
283→	session.FlushLog()
284→	return nil
