287→// runSessionEnd marks a session as ended.
288→func runSessionEnd() error {
289→	input, err := session.ReadStdin()
290→	if err != nil || input == nil || input.SessionID == "" {
291→		return nil
292→	}
293→
294→	if !db.Exists() {
295→		return nil
296→	}
297→	d, err := db.Open()
298→	if err != nil {
299→		return nil
300→	}
301→	defer d.Close()
302→
303→	db.EnsureSessionTables(d)
304→	session.EndSession(d, input.SessionID)
305→	session.AddEvent(d, input.SessionID, "session_end", input)
306→
307→	pushReport := attemptSessionEndPush(d)
308→	if pushReport.Attempted {
309→		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
310→		if pushReport.Error != "" {
311→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
312→		} else {
313→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
314→		}
315→	}
316→
317→	session.Logger().Info("session-end", "session_id", input.SessionID)
318→	session.FlushLog()
319→	return nil
320→}
