501→		b.WriteString("\n")
502→	}
503→
504→	// Rules
505→	b.WriteString("Rules:\n")
506→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
507→	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
508→	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
509→	b.WriteString("- For email stats: nurge emails stats --format json\n")
510→	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
511→	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")
512→
513→	if len(s.skillNames) > 0 {
514→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
515→	}
516→
517→	return b.String()
518→}
