520→func attemptSessionStartSync() *sessionSyncReport {
521→	report := &sessionSyncReport{}
522→
523→	if !db.Exists() {
524→		return report
525→	}
526→
527→	convexURL := strings.TrimSpace(GetConvexURL())
528→	if convexURL == "" {
529→		return report
530→	}
531→
532→	authFile, err := account.LoadAuth()
533→	if err != nil || strings.TrimSpace(authFile.Token) == "" {
534→		return report
535→	}
536→
537→	d, err := db.Open()
538→	if err != nil {
539→		report.Attempted = true
540→		report.Error = shortSyncError(err)
541→		return report
542→	}
543→	defer d.Close()
544→
545→	report.Attempted = true
546→	engine := nurgesync.NewEngine(d, account.NewConvexClient(convexURL), authFile.Token)
547→	pull, err := engine.Pull()
548→	if err != nil {
549→		report.Error = shortSyncError(err)
550→		return report
551→	}
552→
553→	report.RowsUpserted = pull.RowsUpserted
554→	report.TablesUpdated = pull.TablesUpdated
555→	report.PreviousVersion = pull.PreviousVersion
556→	report.CurrentVersion = pull.CurrentVersion
557→
558→	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
559→	if err == nil {
560→		report.Delta = delta
561→	}
562→
563→	return report
564→}
