596→func buildSyncBannerLine(report *sessionSyncReport) string {
597→	if report == nil || !report.Attempted {
598→		return ""
599→	}
600→	if report.Error != "" {
601→		return "Remote sync unavailable — using last local state"
602→	}
603→	if report.RowsUpserted == 0 {
604→		return ""
605→	}
606→
607→	parts := []string{}
608→	if report.Delta != nil {
609→		if report.Delta.TasksSent > 0 {
610→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
611→		}
612→		if report.Delta.RepliesNeedingAttention > 0 {
613→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
614→		}
615→		if report.Delta.TasksFailed > 0 {
616→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
617→		}
618→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
619→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
620→		}
621→	}
622→	if len(parts) == 0 {
623→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
624→	}
625→	return "While you were away: " + strings.Join(parts, " | ")
626→}
