644→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
645→		report.RowsUpserted,
646→		pluralSuffix(report.RowsUpserted),
647→		report.TablesUpdated,
648→		pluralSuffix(report.TablesUpdated),
649→	)
650→
651→	if report.Delta == nil {
652→		return b.String()
653→	}
654→
655→	if report.Delta.TasksSent > 0 {
656→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
657→	}
658→	if report.Delta.TasksFailed > 0 {
659→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
660→	}
661→	if report.Delta.RepliesNeedingAttention > 0 {
662→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
663→		for _, item := range report.Delta.RecentReplies {
664→			if strings.TrimSpace(item.Subject) != "" {
665→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
666→				continue
667→			}
668→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
669→		}
670→	}
671→	if report.Delta.EnrollmentsStopped > 0 {
672→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
673→	}
674→	if report.Delta.EnrollmentsCompleted > 0 {
675→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
676→	}
677→	if report.Delta.SuppressionsAdded > 0 {
678→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
679→	}
680→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
681→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
682→	}
683→
684→	return b.String()
685→}
