687→func shortSyncError(err error) string {
688→	if err == nil {
689→		return ""
690→	}
691→	message := strings.TrimSpace(err.Error())
692→	if len(message) > 120 {
693→		return message[:117] + "..."
694→	}
695→	return message
696→}
697→
698→func pluralSuffix(count int, forms ...string) string {
699→	if len(forms) == 2 {
700→		if count == 1 {
701→			return forms[0]
702→		}
703→		return forms[1]
704→	}
705→	if count == 1 {
706→		return ""
707→	}
708→	return "s"
709→}
