  1→package project
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→	"time"
  9→)
 10→
 11→const configFile = ".nurge/config.json"
 12→
 13→// ConnectorState holds the state of a single connected service.
 14→type ConnectorState struct {
 15→	Connected   bool   `json:"connected"`
 16→	ConnectedAt string `json:"connected_at,omitempty"`
 17→	Account     string `json:"account,omitempty"`
 18→	Type        string `json:"type"` // "crm" or "email"
 19→}
 20→
 21→// Config is the top-level nurge configuration.
 22→type Config struct {
 23→	Version        int                        `json:"version"`
 24→	CreatedAt      string                     `json:"created_at"`
 25→	Connectors     map[string]ConnectorState  `json:"connectors"`
 26→	SetupCompleted bool                       `json:"setup_completed"`
 27→	Settings       map[string]string          `json:"settings,omitempty"`
 28→}
 29→
 30→// Path returns the path to config.json.
 31→func Path() string {
 32→	return configFile
 33→}
 34→
 35→// Default returns a new Config with default values.
 36→func Default() *Config {
 37→	return &Config{
 38→		Version:        1,
 39→		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 40→		Connectors:     make(map[string]ConnectorState),
 41→		SetupCompleted: false,
 42→	}
 43→}
 44→
 45→// Load reads config from disk.
 46→func Load() (*Config, error) {
 47→	data, err := os.ReadFile(configFile)
 48→	if err != nil {
 49→		return nil, fmt.Errorf("reading config: %w", err)
 50→	}
 51→	var cfg Config
 52→	if err := json.Unmarshal(data, &cfg); err != nil {
 53→		return nil, fmt.Errorf("parsing config: %w", err)
 54→	}
 55→	if cfg.Connectors == nil {
 56→		cfg.Connectors = make(map[string]ConnectorState)
 57→	}
 58→	return &cfg, nil
 59→}
 60→
 61→// Write saves config to disk.
 62→func Write(cfg *Config) error {
 63→	data, err := json.MarshalIndent(cfg, "", "  ")
 64→	if err != nil {
 65→		return fmt.Errorf("marshaling config: %w", err)
 66→	}
 67→	if err := os.WriteFile(configFile, data, 0644); err != nil {
 68→		return fmt.Errorf("writing config: %w", err)
 69→	}
 70→	return nil
 71→}
 72→
 73→// SetConnector updates a connector in the config and saves.
 74→func SetConnector(id, connType, account string) error {
 75→	cfg, err := Load()
 76→	if err != nil {
 77→		return err
 78→	}
 79→	cfg.Connectors[id] = ConnectorState{
 80→		Connected:   true,
 81→		ConnectedAt: time.Now().UTC().Format(time.RFC3339),
 82→		Account:     account,
 83→		Type:        connType,
 84→	}
 85→	return Write(cfg)
 86→}
 87→
 88→// RemoveConnector removes a connector from config and saves.
 89→func RemoveConnector(id string) error {
 90→	cfg, err := Load()
 91→	if err != nil {
 92→		return err
 93→	}
 94→	delete(cfg.Connectors, id)
 95→	return Write(cfg)
 96→}
 97→
 98→// Get returns the value for a settings key, or empty string if not set.
 99→func Get(key string) (string, error) {
100→	cfg, err := Load()
101→	if err != nil {
102→		return "", err
103→	}
104→	if cfg.Settings == nil {
105→		return "", nil
106→	}
107→	return cfg.Settings[key], nil
108→}
109→
110→// Set stores a key/value pair in settings and saves the config.
111→func Set(key, value string) error {
112→	cfg, err := Load()
113→	if err != nil {
114→		return err
115→	}
116→	if cfg.Settings == nil {
117→		cfg.Settings = make(map[string]string)
118→	}
119→	cfg.Settings[key] = value
120→	return Write(cfg)
121→}
122→
123→// SetSetupCompleted sets the top-level setup_completed flag and saves.
124→// When marking as complete, also removes the global setup skill — it's no longer needed.
125→func SetSetupCompleted(completed bool) error {
126→	cfg, err := Load()
127→	if err != nil {
128→		return err
129→	}
130→	cfg.SetupCompleted = completed
131→	if err := Write(cfg); err != nil {
132→		return err
133→	}
134→	if completed {
135→		removeSetupSkill()
136→	}
137→	return nil
138→}
