 80→// sessionStatus holds workspace state gathered for banner/prompt output.
 81→type sessionStatus struct {
 82→	configLoaded   bool
 83→	setupCompleted bool
 84→	connectors     map[string]project.ConnectorState
 85→	settings       map[string]string
 86→	emailTotal     int
 87→	outboundTotal  int
 88→	weeklyStats    *email.WeeklyStats
 89→	skillCount     int
 90→	skillNames     []string
 91→	contactCount   int
 92→	learningCount  int
 93→	startSync      *sessionSyncReport
 94→}
 95→
 96→type sessionSyncReport struct {
 97→	Attempted       bool                      `json:"attempted"`
 98→	RowsUpserted    int                       `json:"rows_upserted,omitempty"`
 99→	TablesUpdated   int                       `json:"tables_updated,omitempty"`
100→	PreviousVersion int64                     `json:"previous_version,omitempty"`
101→	CurrentVersion  int64                     `json:"current_version,omitempty"`
102→	Delta           *nurgesync.ExecutionDelta `json:"delta,omitempty"`
103→	Error           string                    `json:"error,omitempty"`
104→}
105→
106→type sessionPushReport struct {
107→	Attempted     bool   `json:"attempted"`
108→	RowsPushed    int    `json:"rows_pushed,omitempty"`
109→	TablesScanned int    `json:"tables_scanned,omitempty"`
110→	Error         string `json:"error,omitempty"`
111→}
112→
113→func gatherStatus() *sessionStatus {
114→	s := &sessionStatus{
115→		settings: make(map[string]string),
116→	}
117→
118→	// Load config (graceful — may not exist)
119→	cfg, err := project.Load()
120→	if err == nil {
121→		s.configLoaded = true
122→		s.setupCompleted = cfg.SetupCompleted
123→		s.connectors = cfg.Connectors
124→		if cfg.Settings != nil {
125→			s.settings = cfg.Settings
126→		}
127→	}
128→
129→	// Load DB stats (graceful — may not exist)
130→	if !db.Exists() {
131→		return s
132→	}
133→	d, err := db.Open()
134→	if err != nil {
135→		return s
136→	}
137→	defer d.Close()
138→
139→	stats, err := email.Stats(d)
140→	if err == nil {
141→		s.emailTotal = stats.Total
142→		s.outboundTotal = stats.ByClass["outbound"]
143→	}
144→
145→	weekly, err := email.ThisWeek(d)
146→	if err == nil {
147→		s.weeklyStats = weekly
148→	}
149→
150→	skills, err := session.ListSkills(d)
151→	if err == nil {
152→		s.skillCount = len(skills)
153→		for _, sk := range skills {
154→			s.skillNames = append(s.skillNames, sk.SkillName)
155→		}
156→	}
157→
158→	// Contact count (graceful)
159→	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
160→
161→	// Learning count (graceful)
162→	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
163→
164→	return s
165→}
