235→// runUserPrompt captures a user prompt submission event.
236→func runUserPrompt() error {
237→	input, err := session.ReadStdin()
238→	if err != nil || input == nil || input.SessionID == "" {
239→		return nil // graceful no-op
240→	}
241→
242→	if !db.Exists() {
243→		return nil
244→	}
245→	d, err := db.Open()
246→	if err != nil {
