248→	}
249→	defer d.Close()
250→
251→	db.EnsureSessionTables(d)
252→	session.AddEvent(d, input.SessionID, "prompt", input)
253→
254→	// Log without prompt content — keep logs lightweight
255→	session.Logger().Info("prompt", "session_id", input.SessionID)
256→	session.FlushLog()
257→	return nil
258→}
