698→func pluralSuffix(count int, forms ...string) string {
699→	if len(forms) == 2 {
700→		if count == 1 {
701→			return forms[0]
702→		}
703→		return forms[1]
704→	}
705→	if count == 1 {
706→		return ""
707→	}
708→	return "s"
709→}
