711→// --- Auto-update ---
712→
713→const (
714→	updateCacheFile   = ".nurge/update_check.json"
715→	updateCheckTTL    = 24 * time.Hour
716→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
717→)
718→
719→type updateCache struct {
720→	LatestVersion string `json:"latest_version"`
721→	CheckedAt     string `json:"checked_at"`
722→	UpdatedAt     string `json:"updated_at,omitempty"`
723→}
724→
725→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
726→// Returns a message for the banner, or empty string.
727→func checkAndAutoUpdate() string {
728→	// Read cache
729→	cache := readUpdateCache()
730→
731→	// If checked recently, just report
732→	if cache != nil && cache.CheckedAt != "" {
733→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
734→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
735→			// Cache is fresh — check if we just updated
736→			if cache.UpdatedAt != "" {
737→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
738→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
739→					// Clear the updated flag for next time
740→					cache.UpdatedAt = ""
741→					writeUpdateCache(cache)
742→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
743→				}
744→			}
745→			return ""
746→		}
747→	}
748→
749→	// Check for latest version (with timeout)
750→	latest := fetchLatestVersion()
751→	if latest == "" {
752→		// Network failed — update cache timestamp so we don't retry immediately
753→		if cache == nil {
754→			cache = &updateCache{}
755→		}
756→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
757→		writeUpdateCache(cache)
758→		return ""
759→	}
760→
761→	// Save to cache
762→	if cache == nil {
763→		cache = &updateCache{}
764→	}
765→	cache.LatestVersion = latest
766→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
767→
768→	// Compare: if current version matches latest, no update needed
769→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
770→		writeUpdateCache(cache)
771→		return ""
772→	}
773→
774→	// Different version — auto-update
775→	if runAutoUpdate() {
776→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
777→		writeUpdateCache(cache)
778→		return fmt.Sprintf("Updating to %s...", latest)
779→	}
780→
781→	writeUpdateCache(cache)
782→	return ""
783→}
784→
785→func readUpdateCache() *updateCache {
786→	data, err := os.ReadFile(updateCacheFile)
787→	if err != nil {
788→		return nil
789→	}
790→	var c updateCache
791→	if err := json.Unmarshal(data, &c); err != nil {
792→		return nil
793→	}
794→	return &c
795→}
796→
797→func writeUpdateCache(c *updateCache) {
798→	data, err := json.Marshal(c)
799→	if err != nil {
800→		return
801→	}
802→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
803→	os.WriteFile(updateCacheFile, data, 0644)
804→}
