806→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
807→func fetchLatestVersion() string {
808→	client := &http.Client{Timeout: 3 * time.Second}
809→	resp, err := client.Get(githubReleasesURL)
810→	if err != nil {
811→		return ""
812→	}
813→	defer resp.Body.Close()
814→
815→	if resp.StatusCode != 200 {
816→		return ""
817→	}
818→
819→	var release struct {
820→		TagName string `json:"tag_name"`
821→	}
822→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
823→		return ""
824→	}
825→	return release.TagName
826→}
827→
828→// runAutoUpdate runs the install script in the background. Returns true if launched.
829→func runAutoUpdate() bool {
830→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
831→	if err := cmd.Start(); err != nil {
832→		return false
833→	}
834→	// Don't wait — let it run in background
835→	go cmd.Wait()
836→	return true
837→}
