 68→					selectedMailbox = campaignMailbox
 69→				}
 70→			}
 71→		}
 72→		if sendSequence != "" {
 73→			effectiveSendType = sequence.SendTypeFirstTouch
 74→		}
 75→		if sendTaskID != "" {
 76→			task, err = sequence.TaskByID(d, sendTaskID)
 77→			if err != nil {
 78→				return err
 79→			}
 80→			effectiveSendType = task.SendType
 81→			selectedMailbox, err = sequence.ResolveTaskMailbox(d, *task, gmail.Account, timeNow())
 82→			if err != nil {
 83→				return err
 84→			}
 85→			if sendTo == "" {
 86→				sendTo = task.ContactEmail
 87→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 88→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 89→			}
 90→			if sendSubject == "" || sendBody == "" {
 91→				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 92→				if err != nil {
 93→					return err
 94→				}
 95→				if sendSubject == "" {
 96→					sendSubject = renderedSubject
 97→				}
 98→				if sendBody == "" {
 99→					sendBody = renderedBody
100→				}
101→			}
102→		}
103→
104→		sentAt := timeNow()
105→		if sendTo == "" {
106→			return fmt.Errorf("recipient (--to) is required")
107→		}
108→		if sendSubject == "" {
109→			return fmt.Errorf("subject (--subject) is required")
110→		}
111→		if sendBody == "" {
112→			return fmt.Errorf("body (--body) is required")
113→		}
114→		if sendSequence != "" {
115→			enrollment, err := sequence.ActiveEnrollmentForContact(d, selectedMailbox.ID, sendTo)
116→			if err != nil {
117→				return err
118→			}
119→			if enrollment != nil {
120→				return fmt.Errorf("%s already has an active sequence enrollment (%s)", sendTo, enrollment.ID)
121→			}
122→		}
123→		if suppression, suppressed, err := sequence.IsSuppressed(d, sendTo); err != nil {
124→			return err
125→		} else if suppressed {
126→			return fmt.Errorf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
127→		}
128→
129→		if err := sequence.CanSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
130→			return err
131→		}
132→
133→		srv, err := email.NewClient("")
134→		if err != nil {
135→			return fmt.Errorf("connecting to Gmail: %w", err)
136→		}
137→		fromAddress := strings.TrimSpace(selectedMailbox.TransportEmail)
138→		if fromAddress == "" {
139→			fromAddress = strings.TrimSpace(selectedMailbox.Email)
140→		}
141→
142→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
143→			To:       sendTo,
144→			Cc:       sendCc,
145→			Subject:  sendSubject,
146→			Body:     sendBody,
147→			ThreadID: chooseSendThreadID(task),
148→		})
149→		if err != nil {
150→			if task != nil {
151→				_ = sequence.MarkTaskAttempt(d, task.ID, sentAt, err)
152→				_ = sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusFailed, "", "", err.Error())
153→				_ = sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
154→					MailboxID:    selectedMailbox.ID,
155→					EnrollmentID: task.EnrollmentID,
156→					TaskID:       task.ID,
157→					ContactEmail: sendTo,
158→					SendType:     effectiveSendType,
159→					Status:       "failed",
160→					Subject:      sendSubject,
161→					Error:        err.Error(),
162→					AttemptedAt:  sentAt,
163→				})
164→			}
165→			return err
166→		}
167→
168→		if err := sequence.RecordSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
169→			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
170→		}
171→		if err := email.StoreEmail(d, &email.RawMessage{
172→			ID:        sent.MessageID,
173→			Source:    "gmail",
174→			Direction: "outbound",
175→			ThreadID:  sent.ThreadID,
176→			Subject:   sendSubject,
177→			FromEmail: fromAddress,
178→			ToEmails:  recipientsJSON(sendTo),
179→			CcEmails:  recipientsJSON(sendCc),
180→			Date:      sentAt.UTC().Format(time.RFC3339),
181→			Labels:    `["SENT"]`,
182→		}); err != nil {
183→			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
184→		}
185→		if task != nil {
186→			if err := sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
187→				return fmt.Errorf("email sent (message ID: %s) but failed to update send state for task %s: %w", sent.MessageID, task.ID, err)
188→			}
189→		}
190→		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
191→			MailboxID:    selectedMailbox.ID,
192→			EnrollmentID: chooseEnrollmentID(task),
193→			TaskID:       chooseTaskID(task),
194→			ContactEmail: sendTo,
195→			SendType:     effectiveSendType,
196→			Status:       "sent",
197→			Subject:      sendSubject,
198→			MessageID:    sent.MessageID,
199→			AttemptedAt:  sentAt,
200→		}); err != nil {
201→			return fmt.Errorf("email sent (message ID: %s) but failed to log send attempt: %w", sent.MessageID, err)
202→		}
203→
204→		fmt.Printf("  ✓ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
205→
206→		if sendSequence != "" {
207→			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
208→				SequenceName: sendSequence,
209→				CampaignName: sendCampaign,
210→				MailboxID:    selectedMailbox.ID,
211→				ContactEmail: sendTo,
212→				ContactName:  sendContactName,
213→				Subject:      sendSubject,
214→				InitialBody:  sendBody,
215→				ThreadID:     sent.ThreadID,
216→				MessageID:    sent.MessageID,
217→				SentAt:       sentAt,
218→			})
219→			if err != nil {
220→				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
221→			}
222→
223→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
224→			if nextTask != nil {
225→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
226→			}
227→		}
228→
229→		if task != nil {
230→			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
231→				TaskID:    task.ID,
232→				ThreadID:  sent.ThreadID,
233→				MessageID: sent.MessageID,
234→				MailboxID: selectedMailbox.ID,
235→				SentAt:    sentAt,
236→			})
237→			if err != nil {
238→				return fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, task.ID, err)
239→			}
240→			if nextTask != nil {
241→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
242→			} else {
243→				fmt.Println("  ↳ Sequence completed")
244→			}
245→		}
246→
247→		return nil
248→	},
249→}
