  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→type hooksStep struct{}
 11→
 12→func (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13→
 14→// hookEntry is a single hook command within a matcher group.
 15→type hookEntry struct {
 16→	command string
 17→}
 18→
 19→// hookGroup defines a matcher group with its hooks for a given event.
 20→type hookGroup struct {
 21→	event   string
 22→	matcher string
 23→	hooks   []hookEntry
 24→}
 25→
 26→// requiredHookGroups defines all hook groups nurge needs installed.
 27→// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
 28→var requiredHookGroups = []hookGroup{
 29→	{
 30→		event:   "PostToolUse",
 31→		matcher: "Bash",
 32→		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
 33→	},
 34→	{
 35→		event:   "SessionStart",
 36→		matcher: "",
 37→		hooks:   []hookEntry{{command: "nurge hook session-start"}},
 38→	},
 39→	{
 40→		event:   "UserPromptSubmit",
 41→		matcher: "",
 42→		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
 43→	},
 44→	{
 45→		event:   "Stop",
 46→		matcher: "",
 47→		hooks:   []hookEntry{{command: "nurge hook stop"}},
 48→	},
 49→	{
 50→		event:   "SessionEnd",
 51→		matcher: "",
 52→		hooks:   []hookEntry{{command: "nurge hook session-end"}},
 53→	},
 54→}
 55→
 56→func (s *hooksStep) Done() (bool, error) {
 57→	data, err := os.ReadFile(claudeSettingsPath())
 58→	if err != nil {
 59→		if os.IsNotExist(err) {
 60→			return false, nil
 61→		}
 62→		return false, err
 63→	}
 64→
 65→	var settings map[string]any
 66→	if err := json.Unmarshal(data, &settings); err != nil {
 67→		return false, nil
 68→	}
 69→
 70→	hooks, ok := settings["hooks"].(map[string]any)
 71→	if !ok {
 72→		return false, nil
 73→	}
 74→
 75→	for _, g := range requiredHookGroups {
 76→		for _, h := range g.hooks {
 77→			if !hookCommandExists(hooks, g.event, h.command) {
 78→				return false, nil
 79→			}
 80→		}
 81→	}
 82→	return true, nil
 83→}
 84→
 85→func (s *hooksStep) Run() error {
 86→	settingsPath := claudeSettingsPath()
 87→
 88→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 89→		return fmt.Errorf("creating .claude/: %w", err)
 90→	}
 91→
 92→	// Load existing settings or start fresh
 93→	settings := make(map[string]any)
 94→	if data, err := os.ReadFile(settingsPath); err == nil {
 95→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
 96→	}
 97→
 98→	hooks, _ := settings["hooks"].(map[string]any)
 99→	if hooks == nil {
100→		hooks = make(map[string]any)
101→	}
102→
103→	for _, g := range requiredHookGroups {
104→		// Collect commands that are missing
105→		var missing []hookEntry
106→		for _, h := range g.hooks {
107→			if !hookCommandExists(hooks, g.event, h.command) {
108→				missing = append(missing, h)
109→			}
110→		}
111→		if len(missing) == 0 {
112→			continue
113→		}
114→
115→		// Find existing matcher entry for this event+matcher, or create one
116→		eventHooks, _ := hooks[g.event].([]any)
117→		matcherIdx := -1
118→		for i, item := range eventHooks {
119→			m, ok := item.(map[string]any)
120→			if !ok {
121→				continue
122→			}
123→			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
124→				matcherIdx = i
125→				break
126→			}
127→		}
128→
129→		if matcherIdx >= 0 {
130→			// Append to existing matcher entry
131→			entry := eventHooks[matcherIdx].(map[string]any)
132→			innerHooks, _ := entry["hooks"].([]any)
133→			for _, h := range missing {
134→				innerHooks = append(innerHooks, map[string]any{
135→					"type":    "command",
136→					"command": h.command,
137→				})
138→			}
139→			entry["hooks"] = innerHooks
140→		} else {
141→			// Create new matcher entry with all hooks
142→			var innerHooks []any
143→			for _, h := range g.hooks {
144→				innerHooks = append(innerHooks, map[string]any{
145→					"type":    "command",
146→					"command": h.command,
147→				})
148→			}
149→			entry := map[string]any{
150→				"matcher": g.matcher,
151→				"hooks":   innerHooks,
152→			}
153→			eventHooks = append(eventHooks, entry)
154→		}
155→		hooks[g.event] = eventHooks
156→	}
157→
158→	settings["hooks"] = hooks
159→
160→	// Sync permissions into the settings
161→	if err := syncPermissionsInto(settings); err != nil {
162→		return err
163→	}
164→
165→	data, err := json.MarshalIndent(settings, "", "  ")
166→	if err != nil {
167→		return fmt.Errorf("marshaling settings: %w", err)
168→	}
169→
170→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
171→		return fmt.Errorf("writing settings: %w", err)
172→	}
173→
174→	return nil
175→}
176→
177→// hookCommandExists checks if a specific command already exists under the given event key.
178→func hookCommandExists(hooks map[string]any, event, command string) bool {
179→	arr, ok := hooks[event].([]any)
180→	if !ok {
181→		return false
182→	}
183→	for _, item := range arr {
184→		m, ok := item.(map[string]any)
185→		if !ok {
186→			continue
187→		}
188→		innerHooks, ok := m["hooks"].([]any)
189→		if !ok {
190→			continue
191→		}
192→		for _, h := range innerHooks {
193→			hm, ok := h.(map[string]any)
194→			if !ok {
195→				continue
196→			}
197→			if cmd, ok := hm["command"].(string); ok && cmd == command {
198→				return true
199→			}
200→		}
201→	}
202→	return false
203→}
204→
205→func containsString(arr []any, s string) bool {
206→	for _, v := range arr {
207→		if str, ok := v.(string); ok && str == s {
208→			return true
209→		}
210→	}
211→	return false
212→}
213→
214→func claudeSettingsPath() string {
215→	return filepath.Join(".claude", "settings.json")
216→}
217→
218→// RequiredPermissions lists all allow-rules nurge needs in .claude/settings.json.
219→// Kept in one place so init and session-start sync stay consistent.
220→var RequiredPermissions = []string{
221→	"Bash(nurge *)",
222→	"Bash(git *)",
223→	"Bash(go *)",
224→	"Bash(curl *)",
225→	"Bash(dig *)",
226→	"Bash(gh *)",
227→	"Bash(which *)",
228→	"Bash(ls *)",
229→	"Bash(mkdir *)",
230→	"Bash(cp *)",
231→	"Bash(mv *)",
232→	"Read",
233→	"Edit",
234→	"Write",
235→	"WebFetch",
236→	"WebSearch",
237→}
238→
239→// syncPermissionsInto ensures all RequiredPermissions are present in the
240→// given settings map (mutates in place).
241→func syncPermissionsInto(settings map[string]any) error {
242→	permissions, _ := settings["permissions"].(map[string]any)
243→	if permissions == nil {
244→		permissions = make(map[string]any)
245→	}
246→	allow, _ := permissions["allow"].([]any)
247→	for _, perm := range RequiredPermissions {
248→		if !containsString(allow, perm) {
249→			allow = append(allow, perm)
250→		}
251→	}
252→	permissions["allow"] = allow
253→	settings["permissions"] = permissions
254→	return nil
255→}
256→
257→// SyncPermissions reads .claude/settings.json, adds any missing required
258→// permissions, and writes the file back. Safe to call on every session start.
259→// Returns (added, error) where added is the number of new permissions inserted.
260→func SyncPermissions() (int, error) {
261→	settingsPath := claudeSettingsPath()
262→
263→	settings := make(map[string]any)
264→	if data, err := os.ReadFile(settingsPath); err == nil {
265→		json.Unmarshal(data, &settings)
266→	} else if os.IsNotExist(err) {
267→		return 0, nil // no settings file, nothing to sync
268→	} else {
269→		return 0, err
270→	}
271→
272→	// Count before
273→	permissions, _ := settings["permissions"].(map[string]any)
274→	allowBefore := 0
275→	if permissions != nil {
276→		if a, ok := permissions["allow"].([]any); ok {
277→			allowBefore = len(a)
278→		}
279→	}
280→
281→	if err := syncPermissionsInto(settings); err != nil {
282→		return 0, err
283→	}
284→
285→	// Count after
286→	permissions, _ = settings["permissions"].(map[string]any)
287→	allowAfter := 0
288→	if a, ok := permissions["allow"].([]any); ok {
289→		allowAfter = len(a)
290→	}
291→
292→	added := allowAfter - allowBefore
293→	if added == 0 {
294→		return 0, nil // nothing changed, skip write
295→	}
296→
297→	data, err := json.MarshalIndent(settings, "", "  ")
298→	if err != nil {
299→		return 0, fmt.Errorf("marshaling settings: %w", err)
300→	}
301→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
302→		return 0, fmt.Errorf("writing settings: %w", err)
303→	}
304→	return added, nil
305→}
