330→const syncStateKey = "_sync_state"
331→
332→// loadSyncState reads the sync cursor from a local config-like store.
333→func (e *Engine) loadSyncState() (*SyncState, error) {
334→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
335→	var data string
336→	err := e.db.QueryRow(
337→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
338→	).Scan(&data)
339→	if err == sql.ErrNoRows {
340→		return &SyncState{}, nil
341→	}
342→	if err != nil {
343→		return nil, err
344→	}
345→
346→	var state SyncState
347→	if err := json.Unmarshal([]byte(data), &state); err != nil {
348→		return &SyncState{}, nil
349→	}
350→	return &state, nil
351→}
352→
353→// saveSyncState persists the sync cursor.
354→func (e *Engine) saveSyncState(state *SyncState) error {
355→	data, err := json.Marshal(state)
356→	if err != nil {
357→		return err
358→	}
359→
360→	_, err = e.db.Exec(`
361→		INSERT INTO connectors (id, type, sync_cursor)
362→		VALUES (?, 'sync', ?)
363→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
364→		syncStateKey, string(data),
365→	)
366→	return err
367→}
