 76→	if err != nil {
 77→		return err
 78→	}
 79→	cfg.Connectors[id] = ConnectorState{
 80→		Connected:   true,
 81→		ConnectedAt: time.Now().UTC().Format(time.RFC3339),
 82→		Account:     account,
 83→		Type:        connType,
 84→	}
