123→		s.connectors = cfg.Connectors
124→		if cfg.Settings != nil {
125→			s.settings = cfg.Settings
126→		}
127→	}
128→
129→	// Load DB stats (graceful — may not exist)
130→	if !db.Exists() {
131→		return s
132→	}
133→	d, err := db.Open()
134→	if err != nil {
135→		return s
136→	}
