142→		s.outboundTotal = stats.ByClass["outbound"]
143→	}
144→
145→	weekly, err := email.ThisWeek(d)
146→	if err == nil {
147→		s.weeklyStats = weekly
148→	}
149→
150→	skills, err := session.ListSkills(d)
151→	if err == nil {
152→		s.skillCount = len(skills)
153→		for _, sk := range skills {
154→			s.skillNames = append(s.skillNames, sk.SkillName)
