628→func buildSyncPromptContext(report *sessionSyncReport) string {
629→	if report == nil || !report.Attempted {
630→		return ""
631→	}
632→
633→	var b strings.Builder
634→	if report.Error != "" {
635→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
636→		return b.String()
637→	}
638→
639→	if report.RowsUpserted == 0 {
640→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
641→		return b.String()
642→	}
643→
644→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
645→		report.RowsUpserted,
646→		pluralSuffix(report.RowsUpserted),
647→		report.TablesUpdated,
648→		pluralSuffix(report.TablesUpdated),
649→	)
650→
651→	if report.Delta == nil {
652→		return b.String()
653→	}
654→
655→	if report.Delta.TasksSent > 0 {
656→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
657→	}
658→	if report.Delta.TasksFailed > 0 {
659→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
660→	}
661→	if report.Delta.RepliesNeedingAttention > 0 {
662→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
663→		for _, item := range report.Delta.RecentReplies {
664→			if strings.TrimSpace(item.Subject) != "" {
665→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
666→				continue
667→			}
668→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
669→		}
670→	}
671→	if report.Delta.EnrollmentsStopped > 0 {
672→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
673→	}
674→	if report.Delta.EnrollmentsCompleted > 0 {
675→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
676→	}
677→	if report.Delta.SuppressionsAdded > 0 {
678→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
679→	}
680→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
681→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
682→	}
683→
684→	return b.String()
685→}
686→
687→func shortSyncError(err error) string {
688→	if err == nil {
689→		return ""
690→	}
691→	message := strings.TrimSpace(err.Error())
692→	if len(message) > 120 {
693→		return message[:117] + "..."
694→	}
695→	return message
696→}
697→
698→func pluralSuffix(count int, forms ...string) string {
699→	if len(forms) == 2 {
700→		if count == 1 {
701→			return forms[0]
702→		}
703→		return forms[1]
704→	}
705→	if count == 1 {
706→		return ""
707→	}
708→	return "s"
709→}
710→
711→// --- Auto-update ---
712→
713→const (
714→	updateCacheFile   = ".nurge/update_check.json"
715→	updateCheckTTL    = 24 * time.Hour
716→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
717→)
718→
719→type updateCache struct {
720→	LatestVersion string `json:"latest_version"`
721→	CheckedAt     string `json:"checked_at"`
722→	UpdatedAt     string `json:"updated_at,omitempty"`
723→}
724→
725→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
726→// Returns a message for the banner, or empty string.
727→func checkAndAutoUpdate() string {
728→	// Read cache
729→	cache := readUpdateCache()
730→
731→	// If checked recently, just report
732→	if cache != nil && cache.CheckedAt != "" {
733→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
734→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
735→			// Cache is fresh — check if we just updated
736→			if cache.UpdatedAt != "" {
737→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
738→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
739→					// Clear the updated flag for next time
740→					cache.UpdatedAt = ""
741→					writeUpdateCache(cache)
742→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
743→				}
744→			}
745→			return ""
746→		}
747→	}
748→
749→	// Check for latest version (with timeout)
750→	latest := fetchLatestVersion()
751→	if latest == "" {
752→		// Network failed — update cache timestamp so we don't retry immediately
753→		if cache == nil {
754→			cache = &updateCache{}
755→		}
756→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
757→		writeUpdateCache(cache)
758→		return ""
759→	}
760→
761→	// Save to cache
762→	if cache == nil {
763→		cache = &updateCache{}
764→	}
765→	cache.LatestVersion = latest
766→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
767→
768→	// Compare: if current version matches latest, no update needed
769→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
770→		writeUpdateCache(cache)
771→		return ""
772→	}
773→
774→	// Different version — auto-update
775→	if runAutoUpdate() {
776→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
777→		writeUpdateCache(cache)
778→		return fmt.Sprintf("Updating to %s...", latest)
779→	}
780→
781→	writeUpdateCache(cache)
782→	return ""
783→}
784→
785→func readUpdateCache() *updateCache {
786→	data, err := os.ReadFile(updateCacheFile)
787→	if err != nil {
788→		return nil
789→	}
790→	var c updateCache
791→	if err := json.Unmarshal(data, &c); err != nil {
792→		return nil
793→	}
794→	return &c
795→}
796→
797→func writeUpdateCache(c *updateCache) {
798→	data, err := json.Marshal(c)
799→	if err != nil {
800→		return
801→	}
802→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
803→	os.WriteFile(updateCacheFile, data, 0644)
804→}
805→
806→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
807→func fetchLatestVersion() string {
808→	client := &http.Client{Timeout: 3 * time.Second}
809→	resp, err := client.Get(githubReleasesURL)
810→	if err != nil {
811→		return ""
812→	}
813→	defer resp.Body.Close()
814→
815→	if resp.StatusCode != 200 {
816→		return ""
817→	}
818→
819→	var release struct {
820→		TagName string `json:"tag_name"`
821→	}
822→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
823→		return ""
824→	}
825→	return release.TagName
826→}
827→
828→// runAutoUpdate runs the install script in the background. Returns true if launched.
829→func runAutoUpdate() bool {
830→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
831→	if err := cmd.Start(); err != nil {
832→		return false
833→	}
834→	// Don't wait — let it run in background
835→	go cmd.Wait()
836→	return true
837→}
838→
839→func capitalize(s string) string {
840→	if s == "" {
841→		return s
842→	}
843→	return strings.ToUpper(s[:1]) + s[1:]
844→}
845→
846→func formatCount(n int) string {
847→	if n >= 1000 {
848→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
849→	}
850→	return fmt.Sprintf("%d", n)
851→}
852→

