247→// runUserPrompt captures a user prompt submission event.
248→func runUserPrompt() error {
249→	input, err := session.ReadStdin()
250→	if err != nil || input == nil || input.SessionID == "" {
251→		return nil // graceful no-op
252→	}
253→
254→	if !db.Exists() {
255→		return nil
256→	}
257→	d, err := db.Open()
258→	if err != nil {
259→		return nil
260→	}
261→	defer d.Close()
262→
263→	db.EnsureSessionTables(d)
264→	session.AddEvent(d, input.SessionID, "prompt", input)
265→
266→	// Log without prompt content — keep logs lightweight
267→	session.Logger().Info("prompt", "session_id", input.SessionID)
268→	session.FlushLog()
269→	return nil
270→}
