272→// runStop captures a stop event and creates a checkpoint.
273→func runStop() error {
274→	input, err := session.ReadStdin()
275→	if err != nil || input == nil || input.SessionID == "" {
276→		return nil
277→	}
278→
279→	if !db.Exists() {
280→		return nil
281→	}
282→	d, err := db.Open()
283→	if err != nil {
284→		return nil
285→	}
286→	defer d.Close()
287→
288→	db.EnsureSessionTables(d)
289→	session.AddEvent(d, input.SessionID, "stop", input)
290→	if len(input.ModifiedFiles) > 0 {
291→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
292→	}
293→
294→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
295→	session.FlushLog()
296→	return nil
297→}
