299→// runSessionEnd marks a session as ended.
300→func runSessionEnd() error {
301→	input, err := session.ReadStdin()
302→	if err != nil || input == nil || input.SessionID == "" {
303→		return nil
304→	}
305→
306→	if !db.Exists() {
307→		return nil
308→	}
309→	d, err := db.Open()
310→	if err != nil {
311→		return nil
312→	}
313→	defer d.Close()
314→
315→	db.EnsureSessionTables(d)
316→	session.EndSession(d, input.SessionID)
317→	session.AddEvent(d, input.SessionID, "session_end", input)
318→
319→	pushReport := attemptSessionEndPush(d)
320→	if pushReport.Attempted {
321→		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
322→		if pushReport.Error != "" {
323→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
324→		} else {
325→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
326→		}
327→	}
328→
329→	session.Logger().Info("session-end", "session_id", input.SessionID)
330→	session.FlushLog()
331→	return nil
332→}
