787→// --- Auto-update ---
788→
789→const (
790→	updateCacheFile   = ".nurge/update_check.json"
791→	updateCheckTTL    = 24 * time.Hour
792→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
793→)
794→
795→type updateCache struct {
796→	LatestVersion string `json:"latest_version"`
797→	CheckedAt     string `json:"checked_at"`
798→	UpdatedAt     string `json:"updated_at,omitempty"`
799→}
800→
801→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
802→// Returns a message for the banner, or empty string.
803→func checkAndAutoUpdate() string {
804→	// Read cache
805→	cache := readUpdateCache()
806→
807→	// If checked recently, just report
808→	if cache != nil && cache.CheckedAt != "" {
809→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
810→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
811→			// Cache is fresh — check if we just updated
812→			if cache.UpdatedAt != "" {
813→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
814→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
815→					// Clear the updated flag for next time
816→					cache.UpdatedAt = ""
817→					writeUpdateCache(cache)
818→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
819→				}
820→			}
821→			return ""
822→		}
823→	}
824→
825→	// Check for latest version (with timeout)
826→	latest := fetchLatestVersion()
827→	if latest == "" {
828→		// Network failed — update cache timestamp so we don't retry immediately
829→		if cache == nil {
830→			cache = &updateCache{}
831→		}
832→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
833→		writeUpdateCache(cache)
834→		return ""
835→	}
836→
837→	// Save to cache
838→	if cache == nil {
839→		cache = &updateCache{}
840→	}
841→	cache.LatestVersion = latest
842→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
843→
844→	// Compare: if current version matches latest, no update needed
845→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
846→		writeUpdateCache(cache)
847→		return ""
848→	}
849→
850→	// Different version — auto-update
851→	if runAutoUpdate() {
852→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
853→		writeUpdateCache(cache)
854→		return fmt.Sprintf("Updating to %s...", latest)
855→	}
856→
857→	writeUpdateCache(cache)
858→	return ""
859→}
860→
861→func readUpdateCache() *updateCache {
862→	data, err := os.ReadFile(updateCacheFile)
863→	if err != nil {
864→		return nil
865→	}
866→	var c updateCache
867→	if err := json.Unmarshal(data, &c); err != nil {
868→		return nil
869→	}
870→	return &c
871→}
872→
873→func writeUpdateCache(c *updateCache) {
874→	data, err := json.Marshal(c)
875→	if err != nil {
876→		return
877→	}
878→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
879→	os.WriteFile(updateCacheFile, data, 0644)
880→}
