882→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
883→func fetchLatestVersion() string {
884→	client := &http.Client{Timeout: 3 * time.Second}
885→	resp, err := client.Get(githubReleasesURL)
886→	if err != nil {
887→		return ""
888→	}
889→	defer resp.Body.Close()
890→
891→	if resp.StatusCode != 200 {
892→		return ""
893→	}
894→
895→	var release struct {
896→		TagName string `json:"tag_name"`
897→	}
898→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
899→		return ""
900→	}
901→	return release.TagName
902→}
