904→// runAutoUpdate runs the install script in the background. Returns true if launched.
905→func runAutoUpdate() bool {
906→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
907→	if err := cmd.Start(); err != nil {
908→		return false
909→	}
910→	// Don't wait — let it run in background
911→	go cmd.Wait()
912→	return true
913→}
