 13→type RawMessage struct {
 14→	ID          string
 15→	Source      string
 16→	Direction   string
 17→	ThreadID    string
 18→	Subject     string
 19→	FromEmail   string
 20→	ToEmails    string // JSON array
 21→	CcEmails    string // JSON array
 22→	Date        string
 23→	Snippet     string
 24→	BodyPreview string
 25→	Labels      string // JSON array
 26→}
