190→// runSessionStart outputs JSON with systemMessage (visible banner) and
191→// additionalContext (LLM context) for the SessionStart hook.
192→// Also captures the session in DB + log.
193→func runSessionStart() error {
194→	// Read stdin (Claude Code sends session info)
195→	input, _ := session.ReadStdin()
196→
197→	// Capture session in DB (graceful — don't fail the hook if DB is missing)
198→	if input != nil && input.SessionID != "" && db.Exists() {
199→		if d, err := db.Open(); err == nil {
200→			db.EnsureSessionTables(d)
201→			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
202→			session.AddEvent(d, input.SessionID, "session_start", input)
203→			d.Close()
204→		}
205→		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
206→		session.FlushLog()
207→	}
208→
209→	// Sync permissions — ensures existing users get any new permissions
210→	// added in later versions. Graceful — never fails the hook.
211→	project.SyncPermissions()
212→
213→	syncReport := attemptSessionStartSync()
214→
215→	// Auto-update check (non-blocking, cached)
216→	updateMsg := checkAndAutoUpdate()
217→
218→	s := gatherStatus()
219→	s.startSync = syncReport
220→
221→	if input != nil && input.SessionID != "" && db.Exists() && syncReport != nil && syncReport.Attempted {
222→		if d, err := db.Open(); err == nil {
223→			db.EnsureSessionTables(d)
224→			session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
225→			d.Close()
226→		}
227→	}
228→
229→	banner := buildBanner(s)
230→	if updateMsg != "" {
231→		banner += "\n  " + updateMsg
232→	}
233→	context := buildPromptContext(s)
234→
235→	out := hookOutput{
236→		SystemMessage: banner,
237→		HookSpecificOut: &hookSpecificOut{
238→			HookEventName:     "SessionStart",
239→			AdditionalContext: context,
240→		},
241→	}
242→
243→	enc := json.NewEncoder(os.Stdout)
244→	return enc.Encode(out)
245→}
