334→func buildBanner(s *sessionStatus) string {
335→	var b strings.Builder
336→	ver := fmt.Sprintf("nurge %s", buildVersion)
337→
338→	// Line 1: Powered by Nurge
339→	b.WriteString("\n\nPowered by Nurge\n")
340→	// Line 2: Version
341→	fmt.Fprintf(&b, "  %s\n", ver)
342→
343→	if !s.configLoaded {
344→		b.WriteString("  Run: nurge to get started")
345→		return b.String()
346→	}
347→
348→	// --- Pre-setup: no connectors yet ---
349→	hasConnectors := false
350→	for _, c := range s.connectors {
351→		if c.Connected {
352→			hasConnectors = true
353→			break
354→		}
355→	}
356→	if !hasConnectors {
357→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
358→		return b.String()
359→	}
360→
361→	// --- Setup in progress ---
362→	if !s.setupCompleted {
363→		name := s.settings["user.name"]
364→		if name != "" {
365→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
366→		} else {
367→			b.WriteString("  Setup in progress.\n")
368→		}
369→		b.WriteString("  Run /nurge:setup to continue where you left off.")
370→		return b.String()
371→	}
372→
373→	// --- Post-setup: compact rotating dashboard ---
374→	name := s.settings["user.name"]
375→	if name != "" {
376→		fmt.Fprintf(&b, "  Hey %s\n", name)
377→	}
378→
379→	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
380→		fmt.Fprintf(&b, "  %s\n", syncLine)
381→	}
382→	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
383→		fmt.Fprintf(&b, "  %s\n", refreshLine)
384→	}
385→
386→	// Always show: KPI progress (the one thing that matters most)
387→	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
388→		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
389→		if s.weeklyStats.UniqueContacts > 0 {
390→			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
391→		}
392→		kpiTarget := s.settings["kpi.daily_emails"]
393→		if kpiTarget != "" {
394→			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
395→		}
396→		b.WriteString("\n")
397→	} else {
398→		goal := s.settings["kpi.goal"]
399→		if goal != "" {
400→			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
401→		}
402→	}
403→
404→	// Rotate one additional insight based on day-of-year
405→	// This keeps the banner fresh without overwhelming
406→	slot := time.Now().YearDay() % 5
407→	switch slot {
408→	case 0: // Sending health
409→		warmup := s.settings["sending.warmup_status"]
410→		domainType := s.settings["sending.domain_type"]
411→		if warmup == "fresh" {
412→			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
413→		} else if domainType == "primary" {
414→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
415→		} else {
416→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
417→		}
418→	case 1: // Data snapshot
419→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
420→		if s.outboundTotal > 0 {
421→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
422→		}
423→		if s.contactCount > 0 {
424→			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
425→		}
426→		b.WriteString("\n")
427→	case 2: // Learnings
428→		if s.learningCount > 0 {
429→			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
430→		} else {
431→			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
432→		}
433→	case 3: // Connected services
434→		var connList []string
435→		for id, c := range s.connectors {
436→			if c.Connected {
437→				connList = append(connList, capitalize(id))
438→			}
439→		}
440→		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
441→	case 4: // Quick action suggestion
442→		actions := []string{
443→			"\"research [company]\" — deep-dive a prospect",
444→			"\"write an email to [persona] at [company]\"",
445→			"\"/nurge:review\" — check your KPI progress",
446→			"\"show my pipeline\" — see what needs attention",
447→		}
448→		pick := time.Now().YearDay() / 5 % len(actions)
449→		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
450→	}
451→
452→	return b.String()
453→}
