630→func buildSyncBannerLine(report *sessionSyncReport) string {
631→	if report == nil || !report.Attempted {
632→		return ""
633→	}
634→	if report.Error != "" {
635→		return "Remote sync unavailable — using last local state"
636→	}
637→	if report.RowsUpserted == 0 {
638→		return ""
639→	}
640→
641→	parts := []string{}
642→	if report.Delta != nil {
643→		if report.Delta.TasksSent > 0 {
644→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
645→		}
646→		if report.Delta.RepliesNeedingAttention > 0 {
647→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
648→		}
649→		if report.Delta.TasksFailed > 0 {
650→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
651→		}
652→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
653→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
654→		}
655→	}
656→	if len(parts) == 0 {
657→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
658→	}
659→	return "While you were away: " + strings.Join(parts, " | ")
660→}
