662→func buildSyncPromptContext(report *sessionSyncReport) string {
663→	if report == nil || !report.Attempted {
664→		return ""
665→	}
666→
667→	var b strings.Builder
668→	if report.Error != "" {
669→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
670→		return b.String()
671→	}
672→
673→	if report.RowsUpserted == 0 {
674→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
675→		return b.String()
676→	}
677→
678→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
679→		report.RowsUpserted,
680→		pluralSuffix(report.RowsUpserted),
681→		report.TablesUpdated,
682→		pluralSuffix(report.TablesUpdated),
683→	)
684→
685→	if report.Delta == nil {
686→		return b.String()
687→	}
688→
689→	if report.Delta.TasksSent > 0 {
690→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
691→	}
692→	if report.Delta.TasksFailed > 0 {
693→		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
694→	}
695→	if report.Delta.RepliesNeedingAttention > 0 {
696→		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
697→		for _, item := range report.Delta.RecentReplies {
698→			if strings.TrimSpace(item.Subject) != "" {
699→				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
700→				continue
701→			}
702→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
703→		}
704→	}
705→	if report.Delta.EnrollmentsStopped > 0 {
706→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
707→	}
708→	if report.Delta.EnrollmentsCompleted > 0 {
709→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
710→	}
711→	if report.Delta.SuppressionsAdded > 0 {
712→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
713→	}
714→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
715→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
716→	}
717→
718→	return b.String()
719→}
