721→func buildSkillRefreshBannerLine(staleSkills []session.StaleSkill) string {
722→	if len(staleSkills) == 0 {
723→		return ""
724→	}
725→	names := make([]string, 0, len(staleSkills))
726→	for i, item := range staleSkills {
727→		if i >= 3 {
728→			break
729→		}
730→		names = append(names, item.SkillName)
731→	}
732→	return fmt.Sprintf("Skills ready for refresh: %s", strings.Join(names, ", "))
733→}
