735→func buildStrategicMemoryPromptContext(memories []session.StrategicMemory, staleSkills []session.StaleSkill) string {
736→	if len(memories) == 0 && len(staleSkills) == 0 {
737→		return ""
738→	}
739→
740→	var b strings.Builder
741→	if len(memories) > 0 {
742→		b.WriteString("Strategic memory updates:\n")
743→		for _, memory := range memories {
744→			fmt.Fprintf(&b, "- %s", memory.Summary)
745→			if len(memory.AffectedSkills) > 0 {
746→				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
747→			}
748→			b.WriteString("\n")
749→		}
750→	}
751→
752→	if len(staleSkills) > 0 {
753→		b.WriteString("Skills likely stale:\n")
754→		for _, item := range staleSkills {
755→			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
756→		}
757→		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
758→	}
759→
760→	return b.String()
761→}
