  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→	"time"
  9→
 10→	gm "google.golang.org/api/gmail/v1"
 11→)
 12→
 13→type RawMessage struct {
 14→	ID          string
 15→	Source      string
 16→	Direction   string
 17→	ThreadID    string
 18→	Subject     string
 19→	FromEmail   string
 20→	ToEmails    string // JSON array
 21→	CcEmails    string // JSON array
 22→	Date        string
 23→	Snippet     string
 24→	BodyPreview string
 25→	Labels      string // JSON array
 26→}
 27→
 28→type SyncResult struct {
 29→	Fetched  int
 30→	Stored   int
 31→	Cursor   string
 32→	Duration time.Duration
 33→}
 34→
 35→func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
 36→	start := time.Now()
 37→	result := &SyncResult{}
 38→
 39→	var cursor string
 40→	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)
 41→
 42→	query := "in:sent"
 43→	if cursor == "" {
 44→		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
 45→		query += " after:" + since
 46→	}
 47→
 48→	var pageToken string
 49→	for {
 50→		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
 51→		if pageToken != "" {
 52→			req = req.PageToken(pageToken)
 53→		}
 54→
 55→		resp, err := req.Do()
 56→		if err != nil {
 57→			return result, fmt.Errorf("listing messages: %w", err)
 58→		}
 59→
 60→		for _, msg := range resp.Messages {
 61→			result.Fetched++
 62→
 63→			if cursor != "" {
 64→				var exists int
 65→				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
 66→				if exists == 1 {
 67→					continue
 68→				}
 69→			}
 70→
 71→			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
 72→				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 73→			if err != nil {
 74→				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
 75→				continue
 76→			}
 77→
 78→			email := parseMessage(full)
 79→			if err := StoreEmail(d, email); err != nil {
 80→				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
 81→				continue
 82→			}
 83→			result.Stored++
 84→		}
 85→
 86→		pageToken = resp.NextPageToken
 87→		if pageToken == "" {
 88→			break
 89→		}
 90→	}
 91→
 92→	result.Cursor = time.Now().UTC().Format(time.RFC3339)
 93→	result.Duration = time.Since(start)
 94→
 95→	d.Exec(
 96→		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
 97→		 VALUES ('gmail', 'email', ?, ?, ?)
 98→		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
 99→		result.Cursor, result.Cursor, result.Stored,
100→		result.Cursor, result.Cursor, result.Stored,
101→	)
102→
103→	return result, nil
104→}
105→
106→func StoreEmail(d *sql.DB, e *RawMessage) error {
107→	source := e.Source
108→	if source == "" {
109→		source = "gmail"
110→	}
111→	direction := e.Direction
112→	if direction == "" {
113→		direction = "outbound"
114→	}
115→
116→	var exists int
117→	isNewMessage := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&exists) == sql.ErrNoRows
118→
119→	_, err := d.Exec(`
120→		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
121→		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
122→		ON CONFLICT(id) DO UPDATE SET
123→			source = excluded.source,
124→			direction = excluded.direction,
125→			subject = excluded.subject,
126→			snippet = excluded.snippet,
127→			body_preview = excluded.body_preview,
128→			labels = excluded.labels,
129→			synced_at = datetime('now')`,
130→		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
131→		e.Date, e.Snippet, e.BodyPreview, e.Labels,
132→	)
133→	if err != nil {
134→		return err
135→	}
136→	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
137→}
138→
139→func parseMessage(msg *gm.Message) *RawMessage {
140→	e := &RawMessage{
141→		ID:        msg.Id,
142→		Source:    "gmail",
143→		Direction: "outbound",
144→		ThreadID:  msg.ThreadId,
145→		Snippet:   msg.Snippet,
146→		CcEmails:  "[]",
147→		ToEmails:  "[]",
148→		Labels:    "[]",
149→	}
150→
151→	for _, h := range msg.Payload.Headers {
152→		switch h.Name {
153→		case "Subject":
154→			e.Subject = h.Value
155→		case "From":
156→			e.FromEmail = extractEmail(h.Value)
157→		case "To":
158→			e.ToEmails = emailsToJSON(h.Value)
159→		case "Cc":
160→			e.CcEmails = emailsToJSON(h.Value)
161→		case "Date":
162→			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
163→				e.Date = t.UTC().Format(time.RFC3339)
164→			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
165→				e.Date = t.UTC().Format(time.RFC3339)
166→			} else {
167→				e.Date = h.Value
168→			}
169→		}
170→	}
171→
172→	if len(msg.LabelIds) > 0 {
173→		labelsJSON, _ := json.Marshal(msg.LabelIds)
174→		e.Labels = string(labelsJSON)
175→	}
176→
177→	return e
178→}
179→
180→func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
181→	timestamp := e.Date
182→	if direction == "inbound" {
183→		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
184→	}
185→
186→	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
187→	for _, recipient := range recipients {
188→		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
189→			return err
190→		}
191→	}
192→	return nil
193→}
194→
195→func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
196→	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
197→	if emailAddress == "" {
198→		return nil
199→	}
200→	domain := ""
201→	parts := strings.SplitN(emailAddress, "@", 2)
202→	if len(parts) == 2 {
203→		domain = parts[1]
204→	}
205→
206→	_, err := d.Exec(`
207→		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
208→		VALUES (?, ?, ?, ?, ?, 1, ?)
209→		ON CONFLICT(source, email) DO UPDATE SET
210→			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
211→			last_activity_at = CASE
212→				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
213→				ELSE contacts.last_activity_at
214→			END,
215→			last_emailed_at = CASE
216→				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
217→				ELSE contacts.last_emailed_at
218→			END,
219→			email_count = contacts.email_count + ?,
220→			updated_at = datetime('now')`,
221→		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
222→	)
223→	return err
224→}
225→
226→func boolToInt(value bool) int {
227→	if value {
228→		return 1
229→	}
230→	return 0
231→}
232→
233→func extractEmail(header string) string {
234→	if i := strings.Index(header, "<"); i != -1 {
235→		if j := strings.Index(header, ">"); j != -1 {
236→			return header[i+1 : j]
237→		}
238→	}
239→	return strings.TrimSpace(header)
240→}
241→
242→func emailsToJSON(header string) string {
243→	if header == "" {
244→		return "[]"
245→	}
246→	parts := strings.Split(header, ",")
247→	emails := make([]string, 0, len(parts))
248→	for _, p := range parts {
249→		emails = append(emails, extractEmail(p))
250→	}
251→	data, _ := json.Marshal(emails)
252→	return string(data)
253→}
