552→func attemptSessionStartSync() *sessionSyncReport {
553→	report := &sessionSyncReport{}
554→
555→	if !db.Exists() {
556→		return report
557→	}
558→
559→	d, err := db.Open()
560→	if err != nil {
561→		report.Attempted = true
562→		report.Error = shortSyncError(err)
563→		return report
564→	}
565→	defer d.Close()
566→
567→	engine := loadSyncEngine(d)
568→	if engine == nil {
569→		return report
570→	}
571→
572→	report.Attempted = true
573→	pull, err := engine.Pull()
574→	if err != nil {
575→		report.Error = shortSyncError(err)
576→		return report
577→	}
578→
579→	report.RowsUpserted = pull.RowsUpserted
580→	report.TablesUpdated = pull.TablesUpdated
581→	report.PreviousVersion = pull.PreviousVersion
582→	report.CurrentVersion = pull.CurrentVersion
583→
584→	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
585→	if err == nil {
586→		report.Delta = delta
587→	}
588→	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
589→	if err == nil {
590→		for _, memory := range memories {
591→			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
592→				Category:       memory.Category,
593→				Summary:        memory.Summary,
594→				AffectedSkills: memory.AffectedSkills,
595→				Evidence:       memory.Evidence,
596→				Source:         memory.Source,
597→				SourceKey:      memory.SourceKey,
598→				Priority:       memory.Priority,
599→			})
600→		}
601→	}
602→
603→	return report
604→}
