package project

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

type hooksStep struct{}

func (s *hooksStep) Name() string { return "Claude Code hooks installed" }

// hookEntry is a single hook command within a matcher group.
type hookEntry struct {
	command string
}

// hookGroup defines a matcher group with its hooks for a given event.
type hookGroup struct {
	event   string
	matcher string
	hooks   []hookEntry
}

// requiredHookGroups defines all hook groups nurge needs installed.
// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
var requiredHookGroups = []hookGroup{
	{
		event:   "PostToolUse",
		matcher: "Bash",
		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
	},
	{
		event:   "SessionStart",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook session-start"}},
	},
	{
		event:   "UserPromptSubmit",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
	},
	{
		event:   "Stop",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook stop"}},
	},
	{
		event:   "SessionEnd",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook session-end"}},
	},
}

func (s *hooksStep) Done() (bool, error) {
	data, err := os.ReadFile(claudeSettingsPath())
	if err != nil {
		if os.IsNotExist(err) {
			return false, nil
		}
		return false, err
	}

	var settings map[string]any
	if err := json.Unmarshal(data, &settings); err != nil {
		return false, nil
	}

	hooks, ok := settings["hooks"].(map[string]any)
	if !ok {
		return false, nil
	}

	for _, g := range requiredHookGroups {
		for _, h := range g.hooks {
			if !hookCommandExists(hooks, g.event, h.command) {
				return false, nil
			}
		}
	}
	return true, nil
}

func (s *hooksStep) Run() error {
	settingsPath := claudeSettingsPath()

	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
		return fmt.Errorf("creating .claude/: %w", err)
	}

	// Load existing settings or start fresh
	settings := make(map[string]any)
	if data, err := os.ReadFile(settingsPath); err == nil {
		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
	}

	hooks, _ := settings["hooks"].(map[string]any)
	if hooks == nil {
		hooks = make(map[string]any)
	}

	for _, g := range requiredHookGroups {
		// Collect commands that are missing
		var missing []hookEntry
		for _, h := range g.hooks {
			if !hookCommandExists(hooks, g.event, h.command) {
				missing = append(missing, h)
			}
		}
		if len(missing) == 0 {
			continue
		}

		// Find existing matcher entry for this event+matcher, or create one
		eventHooks, _ := hooks[g.event].([]any)
		matcherIdx := -1
		for i, item := range eventHooks {
			m, ok := item.(map[string]any)
			if !ok {
				continue
			}
			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
				matcherIdx = i
				break
			}
		}

		if matcherIdx >= 0 {
			// Append to existing matcher entry
			entry := eventHooks[matcherIdx].(map[string]any)
			innerHooks, _ := entry["hooks"].([]any)
			for _, h := range missing {
				innerHooks = append(innerHooks, map[string]any{
					"type":    "command",
					"command": h.command,
				})
			}
			entry["hooks"] = innerHooks
		} else {
			// Create new matcher entry with all hooks
			var innerHooks []any
			for _, h := range g.hooks {
				innerHooks = append(innerHooks, map[string]any{
					"type":    "command",
					"command": h.command,
				})
			}
			entry := map[string]any{
				"matcher": g.matcher,
				"hooks":   innerHooks,
			}
			eventHooks = append(eventHooks, entry)
		}
		hooks[g.event] = eventHooks
	}

	settings["hooks"] = hooks

	// Sync permissions into the settings
	syncPermissionsInto(settings)

	data, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling settings: %w", err)
	}

	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
		return fmt.Errorf("writing settings: %w", err)
	}

	return nil
}

// hookCommandExists checks if a specific command already exists under the given event key.
func hookCommandExists(hooks map[string]any, event, command string) bool {
	arr, ok := hooks[event].([]any)
	if !ok {
		return false
	}
	for _, item := range arr {
		m, ok := item.(map[string]any)
		if !ok {
			continue
		}
		innerHooks, ok := m["hooks"].([]any)
		if !ok {
			continue
		}
		for _, h := range innerHooks {
			hm, ok := h.(map[string]any)
			if !ok {
				continue
			}
			if cmd, ok := hm["command"].(string); ok && cmd == command {
				return true
			}
		}
	}
	return false
}

func containsString(arr []any, s string) bool {
	for _, v := range arr {
		if str, ok := v.(string); ok && str == s {
			return true
		}
	}
	return false
}

func claudeSettingsPath() string {
	return filepath.Join(".claude", "settings.json")
}

// RequiredPermissions lists all allow-rules nurge needs in .claude/settings.json.
// Kept in one place so init and session-start sync stay consistent.
var RequiredPermissions = []string{
	"Bash(nurge *)",
	"Bash(git *)",
	"Bash(go *)",
	"Bash(curl *)",
	"Bash(dig *)",
	"Bash(gh *)",
	"Bash(which *)",
	"Bash(ls *)",
	"Bash(mkdir *)",
	"Bash(cp *)",
	"Bash(mv *)",
	"Read",
	"Edit",
	"Write",
	"WebFetch",
	"WebSearch",
}

// syncPermissionsInto ensures all RequiredPermissions are present in the
// given settings map (mutates in place).
func syncPermissionsInto(settings map[string]any) {
	permissions, _ := settings["permissions"].(map[string]any)
	if permissions == nil {
		permissions = make(map[string]any)
	}
	allow, _ := permissions["allow"].([]any)
	for _, perm := range RequiredPermissions {
		if !containsString(allow, perm) {
			allow = append(allow, perm)
		}
	}
	permissions["allow"] = allow
	settings["permissions"] = permissions
}

// SyncPermissions reads .claude/settings.json, adds any missing required
// permissions, and writes the file back. Safe to call on every session start.
// Returns (added, error) where added is the number of new permissions inserted.
func SyncPermissions() (int, error) {
	settingsPath := claudeSettingsPath()

	settings := make(map[string]any)
	if data, err := os.ReadFile(settingsPath); err == nil {
		json.Unmarshal(data, &settings)
	} else if os.IsNotExist(err) {
		return 0, nil // no settings file, nothing to sync
	} else {
		return 0, err
	}

	// Count before
	permissions, _ := settings["permissions"].(map[string]any)
	allowBefore := 0
	if permissions != nil {
		if a, ok := permissions["allow"].([]any); ok {
			allowBefore = len(a)
		}
	}

	syncPermissionsInto(settings)

	// Count after
	permissions, _ = settings["permissions"].(map[string]any)
	allowAfter := 0
	if a, ok := permissions["allow"].([]any); ok {
		allowAfter = len(a)
	}

	added := allowAfter - allowBefore
	if added == 0 {
		return 0, nil // nothing changed, skip write
	}

	data, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return 0, fmt.Errorf("marshaling settings: %w", err)
	}
	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
		return 0, fmt.Errorf("writing settings: %w", err)
	}
	return added, nil
}

package email

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"strings"
	"time"

	gm "google.golang.org/api/gmail/v1"
)

type RawMessage struct {
	ID          string
	Source      string
	Direction   string
	ThreadID    string
	Subject     string
	FromEmail   string
	ToEmails    string // JSON array
	CcEmails    string // JSON array
	Date        string
	Snippet     string
	BodyPreview string
	Labels      string // JSON array
}

type SyncResult struct {
	Fetched  int
	Stored   int
	Cursor   string
	Duration time.Duration
}

func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
	start := time.Now()
	result := &SyncResult{}

	var cursor string
	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)

	query := "in:sent"
	if cursor == "" {
		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
		query += " after:" + since
	}

	var pageToken string
	for {
		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
		if pageToken != "" {
			req = req.PageToken(pageToken)
		}

		resp, err := req.Do()
		if err != nil {
			return result, fmt.Errorf("listing messages: %w", err)
		}

		for _, msg := range resp.Messages {
			result.Fetched++

			if cursor != "" {
				var exists int
				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
				if exists == 1 {
					continue
				}
			}

			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
			if err != nil {
				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
				continue
			}

			email := parseMessage(full)
			if err := StoreEmail(d, email); err != nil {
				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
				continue
			}
			result.Stored++
		}

		pageToken = resp.NextPageToken
		if pageToken == "" {
			break
		}
	}

	result.Cursor = time.Now().UTC().Format(time.RFC3339)
	result.Duration = time.Since(start)

	d.Exec(
		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
		 VALUES ('gmail', 'email', ?, ?, ?)
		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
		result.Cursor, result.Cursor, result.Stored,
		result.Cursor, result.Cursor, result.Stored,
	)

	return result, nil
}

func StoreEmail(d *sql.DB, e *RawMessage) error {
	source := e.Source
	if source == "" {
		source = "gmail"
	}
	direction := e.Direction
	if direction == "" {
		direction = "outbound"
	}

	var exists int
	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&exists)
	if err != nil && err != sql.ErrNoRows {
		return err
	}
	isNewMessage := err == sql.ErrNoRows

	_, err := d.Exec(`
		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
		ON CONFLICT(id) DO UPDATE SET
			source = excluded.source,
			direction = excluded.direction,
			subject = excluded.subject,
			snippet = excluded.snippet,
			body_preview = excluded.body_preview,
			labels = excluded.labels,
			synced_at = datetime('now')`,
		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
		e.Date, e.Snippet, e.BodyPreview, e.Labels,
	)
	if err != nil {
		return err
	}
	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
}

func parseMessage(msg *gm.Message) *RawMessage {
	e := &RawMessage{
		ID:        msg.Id,
		Source:    "gmail",
		Direction: "outbound",
		ThreadID:  msg.ThreadId,
		Snippet:   msg.Snippet,
		CcEmails:  "[]",
		ToEmails:  "[]",
		Labels:    "[]",
	}

	for _, h := range msg.Payload.Headers {
		switch h.Name {
		case "Subject":
			e.Subject = h.Value
		case "From":
			e.FromEmail = extractEmail(h.Value)
		case "To":
			e.ToEmails = emailsToJSON(h.Value)
		case "Cc":
			e.CcEmails = emailsToJSON(h.Value)
		case "Date":
			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
				e.Date = t.UTC().Format(time.RFC3339)
			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
				e.Date = t.UTC().Format(time.RFC3339)
			} else {
				e.Date = h.Value
			}
		}
	}

	if len(msg.LabelIds) > 0 {
		labelsJSON, _ := json.Marshal(msg.LabelIds)
		e.Labels = string(labelsJSON)
	}

	return e
}

func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
	timestamp := e.Date
	if direction == "inbound" {
		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
	}

	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
	for _, recipient := range recipients {
		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
			return err
		}
	}
	return nil
}

func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
	if emailAddress == "" {
		return nil
	}
	domain := ""
	parts := strings.SplitN(emailAddress, "@", 2)
	if len(parts) == 2 {
		domain = parts[1]
	}

	_, err := d.Exec(`
		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
		VALUES (?, ?, ?, ?, ?, 1, ?)
		ON CONFLICT(source, email) DO UPDATE SET
			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
			last_activity_at = CASE
				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
				ELSE contacts.last_activity_at
			END,
			last_emailed_at = CASE
				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
				ELSE contacts.last_emailed_at
			END,
			email_count = contacts.email_count + ?,
			updated_at = datetime('now')`,
		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
	)
	return err
}

func boolToInt(value bool) int {
	if value {
		return 1
	}
	return 0
}

func extractEmail(header string) string {
	if i := strings.Index(header, "<"); i != -1 {
		if j := strings.Index(header, ">"); j != -1 {
			return header[i+1 : j]
		}
	}
	return strings.TrimSpace(header)
}

func emailsToJSON(header string) string {
	if header == "" {
		return "[]"
	}
	parts := strings.Split(header, ",")
	emails := make([]string, 0, len(parts))
	for _, p := range parts {
		emails = append(emails, extractEmail(p))
	}
	data, _ := json.Marshal(emails)
	return string(data)
}

