541→func attemptSessionStartSync() *sessionSyncReport {
542→	report := &sessionSyncReport{}
543→
544→	if !db.Exists() {
545→		return report
546→	}
547→
548→	d, err := db.Open()
549→	if err != nil {
550→		report.Attempted = true
551→		report.Error = shortSyncError(err)
552→		return report
553→	}
554→	defer d.Close()
555→
556→	engine := loadSyncEngine(d)
557→	if engine == nil {
558→		return report
559→	}
560→
561→	report.Attempted = true
562→	pull, err := engine.Pull()
563→	if err != nil {
564→		report.Error = shortSyncError(err)
565→		return report
566→	}
567→
568→	report.RowsUpserted = pull.RowsUpserted
569→	report.TablesUpdated = pull.TablesUpdated
570→	report.PreviousVersion = pull.PreviousVersion
571→	report.CurrentVersion = pull.CurrentVersion
572→
573→	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
574→	if err == nil {
575→		report.Delta = delta
576→	}
577→	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
578→	if err == nil {
579→		for _, memory := range memories {
580→			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
581→				Category:       memory.Category,
582→				Summary:        memory.Summary,
583→				AffectedSkills: memory.AffectedSkills,
584→				Evidence:       memory.Evidence,
585→				Source:         memory.Source,
586→				SourceKey:      memory.SourceKey,
587→				Priority:       memory.Priority,
588→			})
589→		}
590→	}
591→
592→	return report
593→}
