651→func buildSyncPromptContext(report *sessionSyncReport) string {
652→	if report == nil || !report.Attempted {
653→		return ""
654→	}
655→
656→	var b strings.Builder
657→	if report.Error != "" {
658→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
659→		return b.String()
660→	}
661→
662→	if report.RowsUpserted == 0 {
663→		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
664→		return b.String()
665→	}
666→
667→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
668→		report.RowsUpserted,
669→		pluralSuffix(report.RowsUpserted),
670→		report.TablesUpdated,
671→		pluralSuffix(report.TablesUpdated),
672→	)
673→
674→	if report.Delta == nil {
675→		return b.String()
676→	}
677→
678→	if report.Delta.TasksSent > 0 {
679→		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
