689→				continue
690→			}
691→			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
692→		}
693→	}
694→	if report.Delta.EnrollmentsStopped > 0 {
695→		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
696→	}
697→	if report.Delta.EnrollmentsCompleted > 0 {
698→		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
699→	}
700→	if report.Delta.SuppressionsAdded > 0 {
701→		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
702→	}
703→	if len(report.Delta.AuthExpiredMailboxes) > 0 {
704→		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
705→	}
706→
707→	return b.String()
708→}
