776→// --- Auto-update ---
777→
778→const (
779→	updateCacheFile   = ".nurge/update_check.json"
780→	updateCheckTTL    = 24 * time.Hour
781→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
782→)
783→
784→type updateCache struct {
785→	LatestVersion string `json:"latest_version"`
786→	CheckedAt     string `json:"checked_at"`
787→	UpdatedAt     string `json:"updated_at,omitempty"`
788→}
789→
790→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
791→// Returns a message for the banner, or empty string.
792→func checkAndAutoUpdate() string {
793→	// Read cache
794→	cache := readUpdateCache()
795→
796→	// If checked recently, just report
797→	if cache != nil && cache.CheckedAt != "" {
798→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
799→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
800→			// Cache is fresh — check if we just updated
801→			if cache.UpdatedAt != "" {
802→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
803→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
804→					// Clear the updated flag for next time
805→					cache.UpdatedAt = ""
806→					writeUpdateCache(cache)
807→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
808→				}
809→			}
810→			return ""
811→		}
812→	}
813→
814→	// Check for latest version (with timeout)
815→	latest := fetchLatestVersion()
816→	if latest == "" {
817→		// Network failed — update cache timestamp so we don't retry immediately
818→		if cache == nil {
819→			cache = &updateCache{}
820→		}
821→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
822→		writeUpdateCache(cache)
823→		return ""
824→	}
825→
826→	// Save to cache
827→	if cache == nil {
828→		cache = &updateCache{}
829→	}
830→	cache.LatestVersion = latest
831→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
832→
833→	// Compare: if current version matches latest, no update needed
834→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
835→		writeUpdateCache(cache)
836→		return ""
837→	}
838→
839→	// Different version — auto-update
840→	if runAutoUpdate() {
841→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
842→		writeUpdateCache(cache)
843→		return fmt.Sprintf("Updating to %s...", latest)
844→	}
845→
846→	writeUpdateCache(cache)
847→	return ""
848→}
849→
850→func readUpdateCache() *updateCache {
851→	data, err := os.ReadFile(updateCacheFile)
852→	if err != nil {
853→		return nil
854→	}
855→	var c updateCache
856→	if err := json.Unmarshal(data, &c); err != nil {
857→		return nil
858→	}
859→	return &c
860→}
861→
862→func writeUpdateCache(c *updateCache) {
863→	data, err := json.Marshal(c)
864→	if err != nil {
865→		return
866→	}
867→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
868→	os.WriteFile(updateCacheFile, data, 0644)
869→}
