871→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
872→func fetchLatestVersion() string {
873→	client := &http.Client{Timeout: 3 * time.Second}
874→	resp, err := client.Get(githubReleasesURL)
875→	if err != nil {
876→		return ""
877→	}
878→	defer resp.Body.Close()
879→
880→	if resp.StatusCode != 200 {
881→		return ""
882→	}
883→
884→	var release struct {
885→		TagName string `json:"tag_name"`
886→	}
887→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
888→		return ""
889→	}
890→	return release.TagName
891→}
