893→// runAutoUpdate runs the install script in the background. Returns true if launched.
894→func runAutoUpdate() bool {
895→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
896→	if err := cmd.Start(); err != nil {
897→		return false
898→	}
899→	// Don't wait — let it run in background
900→	go cmd.Wait()
901→	return true
902→}
