153→		if err != nil {
154→			if task != nil {
155→				_ = sequence.MarkTaskAttempt(d, task.ID, sentAt, err)
156→				_ = sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusFailed, "", "", err.Error())
157→				_ = sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
