106→func StoreEmail(d *sql.DB, e *RawMessage) error {
107→	source := e.Source
108→	if source == "" {
109→		source = "gmail"
110→	}
111→	direction := e.Direction
112→	if direction == "" {
113→		direction = "outbound"
114→	}
115→
116→	var exists int
117→	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&exists)
118→	if err != nil && err != sql.ErrNoRows {
119→		return err
120→	}
121→	isNewMessage := err == sql.ErrNoRows
122→
123→	_, err = d.Exec(`
124→		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
125→		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
126→		ON CONFLICT(id) DO UPDATE SET
127→			source = excluded.source,
128→			direction = excluded.direction,
129→			subject = excluded.subject,
130→			snippet = excluded.snippet,
131→			body_preview = excluded.body_preview,
132→			labels = excluded.labels,
133→			synced_at = datetime('now')`,
134→		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
135→		e.Date, e.Snippet, e.BodyPreview, e.Labels,
136→	)
137→	if err != nil {
138→		return err
139→	}
140→	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
141→}
142→
143→func parseMessage(msg *gm.Message) *RawMessage {
144→	e := &RawMessage{
145→		ID:        msg.Id,
146→		Source:    "gmail",
147→		Direction: "outbound",
148→		ThreadID:  msg.ThreadId,
149→		Snippet:   msg.Snippet,
150→		CcEmails:  "[]",
151→		ToEmails:  "[]",
152→		Labels:    "[]",
153→	}
154→
155→	for _, h := range msg.Payload.Headers {
156→		switch h.Name {
157→		case "Subject":
158→			e.Subject = h.Value
159→		case "From":
160→			e.FromEmail = extractEmail(h.Value)
161→		case "To":
162→			e.ToEmails = emailsToJSON(h.Value)
163→		case "Cc":
164→			e.CcEmails = emailsToJSON(h.Value)
165→		case "Date":
166→			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
167→				e.Date = t.UTC().Format(time.RFC3339)
168→			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
169→				e.Date = t.UTC().Format(time.RFC3339)
170→			} else {
171→				e.Date = h.Value
172→			}
173→		}
174→	}
175→
176→	if len(msg.LabelIds) > 0 {
177→		labelsJSON, _ := json.Marshal(msg.LabelIds)
178→		e.Labels = string(labelsJSON)
179→	}
180→
181→	return e
182→}
183→
184→func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
185→	timestamp := e.Date
186→	if direction == "inbound" {
187→		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
188→	}
189→
190→	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
191→	for _, recipient := range recipients {
192→		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
193→			return err
194→		}
195→	}
196→	return nil
197→}
198→
199→func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
200→	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
201→	if emailAddress == "" {
202→		return nil
203→	}
204→	domain := ""
205→	parts := strings.SplitN(emailAddress, "@", 2)
206→	if len(parts) == 2 {
207→		domain = parts[1]
208→	}
209→
210→	_, err := d.Exec(`
211→		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
212→		VALUES (?, ?, ?, ?, ?, 1, ?)
213→		ON CONFLICT(source, email) DO UPDATE SET
214→			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
215→			last_activity_at = CASE
216→				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
217→				ELSE contacts.last_activity_at
218→			END,
219→			last_emailed_at = CASE
220→				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
221→				ELSE contacts.last_emailed_at
222→			END,
223→			email_count = contacts.email_count + ?,
224→			updated_at = datetime('now')`,
225→		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
226→	)
227→	return err
228→}
229→
230→func boolToInt(value bool) int {
231→	if value {
232→		return 1
233→	}
234→	return 0
235→}
236→
237→func extractEmail(header string) string {
238→	if i := strings.Index(header, "<"); i != -1 {
239→		if j := strings.Index(header, ">"); j != -1 {
240→			return header[i+1 : j]
241→		}
242→	}
243→	return strings.TrimSpace(header)
244→}
245→
246→func emailsToJSON(header string) string {
247→	if header == "" {
248→		return "[]"
249→	}
250→	parts := strings.Split(header, ",")
251→	emails := make([]string, 0, len(parts))
252→	for _, p := range parts {
253→		emails = append(emails, extractEmail(p))
254→	}
255→	data, _ := json.Marshal(emails)
256→	return string(data)
257→}
