115→func gatherStatus() *sessionStatus {
116→	s := &sessionStatus{
117→		settings: make(map[string]string),
118→	}
119→
120→	// Load config (graceful — may not exist)
121→	cfg, err := project.Load()
122→	if err == nil {
123→		s.configLoaded = true
124→		s.setupCompleted = cfg.SetupCompleted
125→		s.connectors = cfg.Connectors
126→		if cfg.Settings != nil {
127→			s.settings = cfg.Settings
128→		}
129→	}
130→
131→	// Load DB stats (graceful — may not exist)
132→	if !db.Exists() {
133→		return s
134→	}
135→	d, err := db.Open()
136→	if err != nil {
137→		return s
138→	}
139→	defer d.Close()
140→
141→	stats, err := email.Stats(d)
142→	if err == nil {
143→		s.emailTotal = stats.Total
144→		s.outboundTotal = stats.ByClass["outbound"]
145→	}
146→
147→	weekly, err := email.ThisWeek(d)
148→	if err == nil {
149→		s.weeklyStats = weekly
150→	}
151→
152→	skills, err := session.ListSkills(d)
153→	if err == nil {
154→		s.skillCount = len(skills)
155→		for _, sk := range skills {
156→			s.skillNames = append(s.skillNames, sk.SkillName)
157→		}
158→	}
159→
160→	// Contact count (graceful)
161→	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)
162→
163→	// Learning count (graceful)
164→	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)
165→
166→	memories, err := session.ListStrategicMemory(d, 3)
167→	if err == nil {
168→		s.recentStrategicMemory = memories
169→	}
170→
171→	staleSkills, err := session.ListStaleSkills(d, 5)
172→	if err == nil {
173→		s.staleSkills = staleSkills
174→	}
175→
176→	return s
177→}
