247→// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
248→// Returns (nil, nil, nil) when the hook should silently no-op.
249→func openSessionDB() (*sql.DB, *session.HookInput, error) {
250→	input, err := session.ReadStdin()
251→	if err != nil || input == nil || input.SessionID == "" {
252→		return nil, nil, nil
253→	}
254→	if !db.Exists() {
255→		return nil, nil, nil
256→	}
257→	d, err := db.Open()
258→	if err != nil {
259→		return nil, nil, nil
260→	}
261→	db.EnsureSessionTables(d)
262→	return d, input, nil
263→}
264→
265→// runUserPrompt captures a user prompt submission event.
266→func runUserPrompt() error {
267→	d, input, _ := openSessionDB()
268→	if d == nil {
269→		return nil
270→	}
271→	defer d.Close()
272→
273→	session.AddEvent(d, input.SessionID, "prompt", input)
274→	session.Logger().Info("prompt", "session_id", input.SessionID)
275→	session.FlushLog()
276→	return nil
277→}
278→
279→// runStop captures a stop event and creates a checkpoint.
280→func runStop() error {
281→	d, input, _ := openSessionDB()
282→	if d == nil {
283→		return nil
284→	}
285→	defer d.Close()
286→
287→	session.AddEvent(d, input.SessionID, "stop", input)
288→	if len(input.ModifiedFiles) > 0 {
289→		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
290→	}
291→
292→	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
293→	session.FlushLog()
294→	return nil
295→}
296→
297→// runSessionEnd marks a session as ended.
298→func runSessionEnd() error {
299→	d, input, _ := openSessionDB()
300→	if d == nil {
301→		return nil
302→	}
303→	defer d.Close()
304→
305→	session.EndSession(d, input.SessionID)
306→	session.AddEvent(d, input.SessionID, "session_end", input)
307→
308→	pushReport := attemptSessionEndPush(d)
309→	if pushReport.Attempted {
310→		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
311→		if pushReport.Error != "" {
312→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
313→		} else {
314→			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
315→		}
316→	}
317→
318→	session.Logger().Info("session-end", "session_id", input.SessionID)
319→	session.FlushLog()
320→	return nil
321→}
