323→func buildBanner(s *sessionStatus) string {
324→	var b strings.Builder
325→	ver := fmt.Sprintf("nurge %s", buildVersion)
326→
327→	// Line 1: Powered by Nurge
328→	b.WriteString("\n\nPowered by Nurge\n")
329→	// Line 2: Version
330→	fmt.Fprintf(&b, "  %s\n", ver)
331→
332→	if !s.configLoaded {
333→		b.WriteString("  Run: nurge to get started")
334→		return b.String()
335→	}
336→
337→	// --- Pre-setup: no connectors yet ---
338→	hasConnectors := false
339→	for _, c := range s.connectors {
340→		if c.Connected {
341→			hasConnectors = true
342→			break
343→		}
344→	}
345→	if !hasConnectors {
346→		b.WriteString("  Run /nurge:setup to connect your email and get started.")
347→		return b.String()
348→	}
349→
350→	// --- Setup in progress ---
351→	if !s.setupCompleted {
352→		name := s.settings["user.name"]
353→		if name != "" {
354→			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
355→		} else {
356→			b.WriteString("  Setup in progress.\n")
357→		}
358→		b.WriteString("  Run /nurge:setup to continue where you left off.")
359→		return b.String()
360→	}
361→
362→	// --- Post-setup: compact rotating dashboard ---
363→	name := s.settings["user.name"]
364→	if name != "" {
365→		fmt.Fprintf(&b, "  Hey %s\n", name)
366→	}
367→
368→	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
369→		fmt.Fprintf(&b, "  %s\n", syncLine)
370→	}
371→	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
372→		fmt.Fprintf(&b, "  %s\n", refreshLine)
373→	}
374→
375→	// Always show: KPI progress (the one thing that matters most)
376→	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
377→		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
378→		if s.weeklyStats.UniqueContacts > 0 {
379→			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
380→		}
381→		kpiTarget := s.settings["kpi.daily_emails"]
382→		if kpiTarget != "" {
383→			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
384→		}
385→		b.WriteString("\n")
386→	} else {
387→		goal := s.settings["kpi.goal"]
388→		if goal != "" {
389→			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
390→		}
391→	}
392→
393→	// Rotate one additional insight based on day-of-year
394→	// This keeps the banner fresh without overwhelming
395→	slot := time.Now().YearDay() % 5
396→	switch slot {
397→	case 0: // Sending health
398→		warmup := s.settings["sending.warmup_status"]
399→		domainType := s.settings["sending.domain_type"]
400→		if warmup == "fresh" {
401→			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
402→		} else if domainType == "primary" {
403→			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
404→		} else {
405→			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
406→		}
407→	case 1: // Data snapshot
408→		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
409→		if s.outboundTotal > 0 {
410→			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
411→		}
412→		if s.contactCount > 0 {
413→			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
414→		}
415→		b.WriteString("\n")
416→	case 2: // Learnings
417→		if s.learningCount > 0 {
418→			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
419→		} else {
420→			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
421→		}
422→	case 3: // Connected services
423→		var connList []string
424→		for id, c := range s.connectors {
425→			if c.Connected {
426→				connList = append(connList, capitalize(id))
427→			}
428→		}
429→		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
430→	case 4: // Quick action suggestion
431→		actions := []string{
432→			"\"research [company]\" — deep-dive a prospect",
433→			"\"write an email to [persona] at [company]\"",
434→			"\"/nurge:review\" — check your KPI progress",
435→			"\"show my pipeline\" — see what needs attention",
436→		}
437→		pick := time.Now().YearDay() / 5 % len(actions)
438→		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
439→	}
440→
441→	return b.String()
442→}
