444→func buildPromptContext(s *sessionStatus) string {
445→	var b strings.Builder
446→
447→	if !s.configLoaded || !s.setupCompleted {
448→		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
449→		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
450→		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
451→		return b.String()
452→	}
453→
454→	// User context
455→	name := s.settings["user.name"]
456→	role := s.settings["user.role"]
457→	if name != "" {
458→		fmt.Fprintf(&b, "User: %s", name)
459→		if role != "" {
460→			fmt.Fprintf(&b, " (%s)", role)
461→		}
462→		b.WriteString("\n")
463→	}
464→
465→	b.WriteString("You are in a Nurge outbound sales workspace.\n")
466→	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
467→		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)
468→
469→	if syncContext := buildSyncPromptContext(s.startSync); syncContext != "" {
470→		b.WriteString(syncContext)
471→	}
472→	if strategicContext := buildStrategicMemoryPromptContext(s.recentStrategicMemory, s.staleSkills); strategicContext != "" {
473→		b.WriteString(strategicContext)
474→	}
475→
476→	// KPI context
477→	goal := s.settings["kpi.goal"]
478→	dailyTarget := s.settings["kpi.daily_emails"]
479→	weeklyMeetings := s.settings["kpi.weekly_meetings"]
480→	if goal != "" {
481→		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
482→		if dailyTarget != "" {
483→			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
484→		}
485→		if weeklyMeetings != "" {
486→			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
487→		}
488→		b.WriteString("\n")
489→	}
490→
491→	// Sending context
492→	warmup := s.settings["sending.warmup_status"]
493→	domainType := s.settings["sending.domain_type"]
494→	if warmup == "fresh" {
495→		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
496→	}
497→	if domainType == "primary" {
498→		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
499→	}
500→
501→	// Geography / compliance
502→	geo := s.settings["prospects.geography"]
503→	if geo != "" {
504→		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
505→		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
506→			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
507→		}
508→		b.WriteString("\n")
509→	}
510→
511→	// Rules
512→	b.WriteString("Rules:\n")
513→	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
514→	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
515→	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
516→	b.WriteString("- For email stats: nurge emails stats --format json\n")
517→	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
518→	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")
519→
520→	if len(s.skillNames) > 0 {
521→		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
522→	}
523→
524→	return b.String()
525→}
