527→// loadSyncEngine creates a sync engine if Convex URL and auth are available.
528→// Returns nil if sync is not configured.
529→func loadSyncEngine(d *sql.DB) *nurgesync.Engine {
530→	convexURL := strings.TrimSpace(GetConvexURL())
531→	if convexURL == "" {
532→		return nil
533→	}
534→	authFile, err := account.LoadAuth()
