619→func buildSyncBannerLine(report *sessionSyncReport) string {
620→	if report == nil || !report.Attempted {
621→		return ""
622→	}
623→	if report.Error != "" {
624→		return "Remote sync unavailable — using last local state"
625→	}
626→	if report.RowsUpserted == 0 {
627→		return ""
628→	}
629→
630→	parts := []string{}
631→	if report.Delta != nil {
632→		if report.Delta.TasksSent > 0 {
633→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
634→		}
635→		if report.Delta.RepliesNeedingAttention > 0 {
636→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
637→		}
638→		if report.Delta.TasksFailed > 0 {
639→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
640→		}
641→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
642→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
643→		}
644→	}
645→	if len(parts) == 0 {
646→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
647→	}
648→	return "While you were away: " + strings.Join(parts, " | ")
649→}
