// sessionStatus holds workspace state gathered for banner/prompt output.
type sessionStatus struct {
	configLoaded          bool
	setupCompleted        bool
	connectors            map[string]project.ConnectorState
	settings              map[string]string
	emailTotal            int
	outboundTotal         int
	weeklyStats           *email.WeeklyStats
	skillCount            int
	skillNames            []string
	contactCount          int
	learningCount         int
	recentStrategicMemory []session.StrategicMemory
	staleSkills           []session.StaleSkill
	startSync             *sessionSyncReport
}

type sessionSyncReport struct {
	Attempted       bool                      `json:"attempted"`
	RowsUpserted    int                       `json:"rows_upserted,omitempty"`
	TablesUpdated   int                       `json:"tables_updated,omitempty"`
	PreviousVersion int64                     `json:"previous_version,omitempty"`
	CurrentVersion  int64                     `json:"current_version,omitempty"`
	Delta           *nurgesync.ExecutionDelta `json:"delta,omitempty"`
	Error           string                    `json:"error,omitempty"`
}

type sessionPushReport struct {
	Attempted     bool   `json:"attempted"`
	RowsPushed    int    `json:"rows_pushed,omitempty"`
	TablesScanned int    `json:"tables_scanned,omitempty"`
	Error         string `json:"error,omitempty"`
}

func gatherStatus() *sessionStatus {
	s := &sessionStatus{
		settings: make(map[string]string),
	}

	// Load config (graceful — may not exist)
	cfg, err := project.Load()
	if err == nil {
		s.configLoaded = true
		s.setupCompleted = cfg.SetupCompleted
		s.connectors = cfg.Connectors
		if cfg.Settings != nil {
			s.settings = cfg.Settings
		}
	}

	// Load DB stats (graceful — may not exist)
	if !db.Exists() {
		return s
	}
	d, err := db.Open()
	if err != nil {
		return s
	}
	defer d.Close()

	stats, err := email.Stats(d)
	if err == nil {
		s.emailTotal = stats.Total
		s.outboundTotal = stats.ByClass["outbound"]
	}

	weekly, err := email.ThisWeek(d)
	if err == nil {
		s.weeklyStats = weekly
	}

	skills, err := session.ListSkills(d)
	if err == nil {
		s.skillCount = len(skills)
		for _, sk := range skills {
			s.skillNames = append(s.skillNames, sk.SkillName)
		}
	}

	// Contact count (graceful)
	d.QueryRow("SELECT COUNT(*) FROM contacts").Scan(&s.contactCount)

	// Learning count (graceful)
	d.QueryRow("SELECT COUNT(*) FROM learnings").Scan(&s.learningCount)

	memories, err := session.ListStrategicMemory(d, 3)
	if err == nil {
		s.recentStrategicMemory = memories
	}

	staleSkills, err := session.ListStaleSkills(d, 5)
	if err == nil {
		s.staleSkills = staleSkills
	}

	return s
}

// hookOutput is the JSON structure Claude Code expects from hook stdout.
type hookOutput struct {
	SystemMessage   string           `json:"systemMessage,omitempty"`
	HookSpecificOut *hookSpecificOut `json:"hookSpecificOutput,omitempty"`
}

type hookSpecificOut struct {
	HookEventName     string `json:"hookEventName"`
	AdditionalContext string `json:"additionalContext,omitempty"`
}

// runSessionStart outputs JSON with systemMessage (visible banner) and
// additionalContext (LLM context) for the SessionStart hook.
// Also captures the session in DB + log.
func runSessionStart() error {
	// Read stdin (Claude Code sends session info)
	input, _ := session.ReadStdin()

	// Capture session in DB (graceful — don't fail the hook if DB is missing)
	if input != nil && input.SessionID != "" && db.Exists() {
		if d, err := db.Open(); err == nil {
			db.EnsureSessionTables(d)
			session.CreateSession(d, input.SessionID, input.Model, input.Source, input.TranscriptPath)
			session.AddEvent(d, input.SessionID, "session_start", input)
			d.Close()
		}
		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
		session.FlushLog()
	}

	// Sync permissions — ensures existing users get any new permissions
	// added in later versions. Graceful — never fails the hook.
	project.SyncPermissions()

	syncReport := attemptSessionStartSync()

	// Auto-update check (non-blocking, cached)
	updateMsg := checkAndAutoUpdate()

	s := gatherStatus()
	s.startSync = syncReport

	if input != nil && input.SessionID != "" && db.Exists() && syncReport != nil && syncReport.Attempted {
		if d, err := db.Open(); err == nil {
			db.EnsureSessionTables(d)
			session.AddEvent(d, input.SessionID, "sync_pull", syncReport)
			d.Close()
		}
	}

	banner := buildBanner(s)
	if updateMsg != "" {
		banner += "\n  " + updateMsg
	}
	context := buildPromptContext(s)

	out := hookOutput{
		SystemMessage: banner,
		HookSpecificOut: &hookSpecificOut{
			HookEventName:     "SessionStart",
			AdditionalContext: context,
		},
	}

	enc := json.NewEncoder(os.Stdout)
	return enc.Encode(out)
}

// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
// Returns (nil, nil, nil) when the hook should silently no-op.
func openSessionDB() (*sql.DB, *session.HookInput, error) {
	input, err := session.ReadStdin()
	if err != nil || input == nil || input.SessionID == "" {
		return nil, nil, nil
	}
	if !db.Exists() {
		return nil, nil, nil
	}
	d, err := db.Open()
	if err != nil {
		return nil, nil, nil
	}
	db.EnsureSessionTables(d)
	return d, input, nil
}

// runUserPrompt captures a user prompt submission event.
func runUserPrompt() error {
	d, input, _ := openSessionDB()
	if d == nil {
		return nil
	}
	defer d.Close()

	session.AddEvent(d, input.SessionID, "prompt", input)
	session.Logger().Info("prompt", "session_id", input.SessionID)
	session.FlushLog()
	return nil
}

// runStop captures a stop event and creates a checkpoint.
func runStop() error {
	d, input, _ := openSessionDB()
	if d == nil {
		return nil
	}
	defer d.Close()

	session.AddEvent(d, input.SessionID, "stop", input)
	if len(input.ModifiedFiles) > 0 {
		session.AddCheckpoint(d, input.SessionID, input.ModifiedFiles)
	}

	session.Logger().Info("stop", "session_id", input.SessionID, "reason", input.StopReason)
	session.FlushLog()
	return nil
}

// runSessionEnd marks a session as ended.
func runSessionEnd() error {
	d, input, _ := openSessionDB()
	if d == nil {
		return nil
	}
	defer d.Close()

	session.EndSession(d, input.SessionID)
	session.AddEvent(d, input.SessionID, "session_end", input)

	pushReport := attemptSessionEndPush(d)
	if pushReport.Attempted {
		session.AddEvent(d, input.SessionID, "sync_push", pushReport)
		if pushReport.Error != "" {
			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "error", pushReport.Error)
		} else {
			session.Logger().Info("session-sync-push", "session_id", input.SessionID, "rows_pushed", pushReport.RowsPushed)
		}
	}

	session.Logger().Info("session-end", "session_id", input.SessionID)
	session.FlushLog()
	return nil
}

func buildBanner(s *sessionStatus) string {
	var b strings.Builder
	ver := fmt.Sprintf("nurge %s", buildVersion)

	// Line 1: Powered by Nurge
	b.WriteString("\n\nPowered by Nurge\n")
	// Line 2: Version
	fmt.Fprintf(&b, "  %s\n", ver)

	if !s.configLoaded {
		b.WriteString("  Run: nurge to get started")
		return b.String()
	}

	// --- Pre-setup: no connectors yet ---
	hasConnectors := false
	for _, c := range s.connectors {
		if c.Connected {
			hasConnectors = true
			break
		}
	}
	if !hasConnectors {
		b.WriteString("  Run /nurge:setup to connect your email and get started.")
		return b.String()
	}

	// --- Setup in progress ---
	if !s.setupCompleted {
		name := s.settings["user.name"]
		if name != "" {
			fmt.Fprintf(&b, "  Hey %s, setup in progress.\n", name)
		} else {
			b.WriteString("  Setup in progress.\n")
		}
		b.WriteString("  Run /nurge:setup to continue where you left off.")
		return b.String()
	}

	// --- Post-setup: compact rotating dashboard ---
	name := s.settings["user.name"]
	if name != "" {
		fmt.Fprintf(&b, "  Hey %s\n", name)
	}

	if syncLine := buildSyncBannerLine(s.startSync); syncLine != "" {
		fmt.Fprintf(&b, "  %s\n", syncLine)
	}
	if refreshLine := buildSkillRefreshBannerLine(s.staleSkills); refreshLine != "" {
		fmt.Fprintf(&b, "  %s\n", refreshLine)
	}

	// Always show: KPI progress (the one thing that matters most)
	if s.weeklyStats != nil && s.weeklyStats.OutboundSent > 0 {
		fmt.Fprintf(&b, "  This week: %d emails sent", s.weeklyStats.OutboundSent)
		if s.weeklyStats.UniqueContacts > 0 {
			fmt.Fprintf(&b, " → %d contacts", s.weeklyStats.UniqueContacts)
		}
		kpiTarget := s.settings["kpi.daily_emails"]
		if kpiTarget != "" {
			fmt.Fprintf(&b, " (target: %s/day)", kpiTarget)
		}
		b.WriteString("\n")
	} else {
		goal := s.settings["kpi.goal"]
		if goal != "" {
			fmt.Fprintf(&b, "  Goal: %s — no emails sent this week yet\n", goal)
		}
	}

	// Rotate one additional insight based on day-of-year
	// This keeps the banner fresh without overwhelming
	slot := time.Now().YearDay() % 5
	switch slot {
	case 0: // Sending health
		warmup := s.settings["sending.warmup_status"]
		domainType := s.settings["sending.domain_type"]
		if warmup == "fresh" {
			b.WriteString("  Domain is fresh — warmup in progress, conservative limits active\n")
		} else if domainType == "primary" {
			b.WriteString("  Sending from primary domain — consider a dedicated outbound domain\n")
		} else {
			fmt.Fprintf(&b, "  %s emails synced | %d skills active\n", formatCount(s.emailTotal), s.skillCount)
		}
	case 1: // Data snapshot
		fmt.Fprintf(&b, "  Data: %s emails", formatCount(s.emailTotal))
		if s.outboundTotal > 0 {
			fmt.Fprintf(&b, " (%d outbound)", s.outboundTotal)
		}
		if s.contactCount > 0 {
			fmt.Fprintf(&b, " | %d contacts", s.contactCount)
		}
		b.WriteString("\n")
	case 2: // Learnings
		if s.learningCount > 0 {
			fmt.Fprintf(&b, "  %d learnings captured — skills improving with every session\n", s.learningCount)
		} else {
			fmt.Fprintf(&b, "  %d skills active | Start sending to build learnings\n", s.skillCount)
		}
	case 3: // Connected services
		var connList []string
		for id, c := range s.connectors {
			if c.Connected {
				connList = append(connList, capitalize(id))
			}
		}
		fmt.Fprintf(&b, "  Connected: %s | %d skills active\n", strings.Join(connList, ", "), s.skillCount)
	case 4: // Quick action suggestion
		actions := []string{
			"\"research [company]\" — deep-dive a prospect",
			"\"write an email to [persona] at [company]\"",
			"\"/nurge:review\" — check your KPI progress",
			"\"show my pipeline\" — see what needs attention",
		}
		pick := time.Now().YearDay() / 5 % len(actions)
		fmt.Fprintf(&b, "  Try: %s\n", actions[pick])
	}

	return b.String()
}

func buildPromptContext(s *sessionStatus) string {
	var b strings.Builder

	if !s.configLoaded || !s.setupCompleted {
		b.WriteString("You are in a Nurge workspace. Setup is not complete. ")
		b.WriteString("Guide the user to run /nurge:setup to finish configuration. ")
		b.WriteString("Do not attempt to use nurge data commands — they will have no data yet.")
		return b.String()
	}

	// User context
	name := s.settings["user.name"]
	role := s.settings["user.role"]
	if name != "" {
		fmt.Fprintf(&b, "User: %s", name)
		if role != "" {
			fmt.Fprintf(&b, " (%s)", role)
		}
		b.WriteString("\n")
	}

	b.WriteString("You are in a Nurge outbound sales workspace.\n")
	fmt.Fprintf(&b, "Status: Setup complete. %s emails synced (%d outbound). %d contacts. %d skills active.\n",
		formatCount(s.emailTotal), s.outboundTotal, s.contactCount, s.skillCount)

	if syncContext := buildSyncPromptContext(s.startSync); syncContext != "" {
		b.WriteString(syncContext)
	}
	if strategicContext := buildStrategicMemoryPromptContext(s.recentStrategicMemory, s.staleSkills); strategicContext != "" {
		b.WriteString(strategicContext)
	}

	// KPI context
	goal := s.settings["kpi.goal"]
	dailyTarget := s.settings["kpi.daily_emails"]
	weeklyMeetings := s.settings["kpi.weekly_meetings"]
	if goal != "" {
		fmt.Fprintf(&b, "Outbound goal: %s.", goal)
		if dailyTarget != "" {
			fmt.Fprintf(&b, " Daily target: %s emails.", dailyTarget)
		}
		if weeklyMeetings != "" {
			fmt.Fprintf(&b, " Weekly meeting target: %s.", weeklyMeetings)
		}
		b.WriteString("\n")
	}

	// Sending context
	warmup := s.settings["sending.warmup_status"]
	domainType := s.settings["sending.domain_type"]
	if warmup == "fresh" {
		b.WriteString("IMPORTANT: Domain is fresh/not warmed up. Enforce conservative sending limits. Do not exceed daily target.\n")
	}
	if domainType == "primary" {
		b.WriteString("Note: User is sending from primary business domain. Be conservative with volume.\n")
	}

	// Geography / compliance
	geo := s.settings["prospects.geography"]
	if geo != "" {
		fmt.Fprintf(&b, "Prospect geography: %s.", geo)
		if strings.Contains(strings.ToLower(geo), "eu") || strings.Contains(strings.ToLower(geo), "europe") {
			b.WriteString(" GDPR applies — ensure legitimate interest basis for outreach.")
		}
		b.WriteString("\n")
	}

	// Rules
	b.WriteString("Rules:\n")
	b.WriteString("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.\n")
	b.WriteString("- For ICP, personas, and product context: nurge config show --format json\n")
	b.WriteString("- For email patterns and insights: nurge context generate --format json\n")
	b.WriteString("- For email stats: nurge emails stats --format json\n")
	b.WriteString("- When sending emails: nurge send (always get user approval first)\n")
	b.WriteString("- When researching prospects: use WebSearch with multiple angles, check company legal pages (mentions légales, impressum), cross-reference before drafting")

	if len(s.skillNames) > 0 {
		fmt.Fprintf(&b, "\nAvailable skills: %s", strings.Join(s.skillNames, ", "))
	}

	return b.String()
}

// loadSyncEngine creates a sync engine if Convex URL and auth are available.
// Returns nil if sync is not configured.
func loadSyncEngine(d *sql.DB) *nurgesync.Engine {
	convexURL := strings.TrimSpace(GetConvexURL())
	if convexURL == "" {
		return nil
	}
	authFile, err := account.LoadAuth()
	if err != nil || strings.TrimSpace(authFile.Token) == "" {
		return nil
	}
	return nurgesync.NewEngine(d, account.NewConvexClient(convexURL), authFile.Token)
}

func attemptSessionStartSync() *sessionSyncReport {
	report := &sessionSyncReport{}

	if !db.Exists() {
		return report
	}

	d, err := db.Open()
	if err != nil {
		report.Attempted = true
		report.Error = shortSyncError(err)
		return report
	}
	defer d.Close()

	engine := loadSyncEngine(d)
	if engine == nil {
		return report
	}

	report.Attempted = true
	pull, err := engine.Pull()
	if err != nil {
		report.Error = shortSyncError(err)
		return report
	}

	report.RowsUpserted = pull.RowsUpserted
	report.TablesUpdated = pull.TablesUpdated
	report.PreviousVersion = pull.PreviousVersion
	report.CurrentVersion = pull.CurrentVersion

	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
	if err == nil {
		report.Delta = delta
	}
	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
	if err == nil {
		for _, memory := range memories {
			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
				Category:       memory.Category,
				Summary:        memory.Summary,
				AffectedSkills: memory.AffectedSkills,
				Evidence:       memory.Evidence,
				Source:         memory.Source,
				SourceKey:      memory.SourceKey,
				Priority:       memory.Priority,
			})
		}
	}

	return report
}

func attemptSessionEndPush(d *sql.DB) *sessionPushReport {
	report := &sessionPushReport{}

	if d == nil {
		return report
	}

	engine := loadSyncEngine(d)
	if engine == nil {
		return report
	}

	report.Attempted = true
	push, err := engine.Push()
	if err != nil {
		report.Error = shortSyncError(err)
		return report
	}

	report.RowsPushed = push.RowsPushed
	report.TablesScanned = push.TablesScanned
	return report
}

func buildSyncBannerLine(report *sessionSyncReport) string {
	if report == nil || !report.Attempted {
		return ""
	}
	if report.Error != "" {
		return "Remote sync unavailable — using last local state"
	}
	if report.RowsUpserted == 0 {
		return ""
	}

	parts := []string{}
	if report.Delta != nil {
		if report.Delta.TasksSent > 0 {
			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
		}
		if report.Delta.RepliesNeedingAttention > 0 {
			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
		}
		if report.Delta.TasksFailed > 0 {
			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
		}
		if len(report.Delta.AuthExpiredMailboxes) > 0 {
			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
		}
	}
	if len(parts) == 0 {
		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
	}
	return "While you were away: " + strings.Join(parts, " | ")
}

func buildSyncPromptContext(report *sessionSyncReport) string {
	if report == nil || !report.Attempted {
		return ""
	}

	var b strings.Builder
	if report.Error != "" {
		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
		return b.String()
	}

	if report.RowsUpserted == 0 {
		b.WriteString("Remote sync status: no new execution-state changes since the last session.\n")
		return b.String()
	}

	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
		report.RowsUpserted,
		pluralSuffix(report.RowsUpserted),
		report.TablesUpdated,
		pluralSuffix(report.TablesUpdated),
	)

	if report.Delta == nil {
		return b.String()
	}

	if report.Delta.TasksSent > 0 {
		fmt.Fprintf(&b, "Remote sends completed: %d.\n", report.Delta.TasksSent)
	}
	if report.Delta.TasksFailed > 0 {
		fmt.Fprintf(&b, "Remote send failures: %d. Check `nurge tasks list` and `nurge sends list` before advancing sequences.\n", report.Delta.TasksFailed)
	}
	if report.Delta.RepliesNeedingAttention > 0 {
		fmt.Fprintf(&b, "Replies needing attention: %d. Check `nurge replies queue` early in the session.\n", report.Delta.RepliesNeedingAttention)
		for _, item := range report.Delta.RecentReplies {
			if strings.TrimSpace(item.Subject) != "" {
				fmt.Fprintf(&b, "- Reply: %s (%s) — %s\n", item.ContactEmail, item.Classification, item.Subject)
				continue
			}
			fmt.Fprintf(&b, "- Reply: %s (%s)\n", item.ContactEmail, item.Classification)
		}
	}
	if report.Delta.EnrollmentsStopped > 0 {
		fmt.Fprintf(&b, "Enrollments stopped remotely: %d.\n", report.Delta.EnrollmentsStopped)
	}
	if report.Delta.EnrollmentsCompleted > 0 {
		fmt.Fprintf(&b, "Enrollments completed remotely: %d.\n", report.Delta.EnrollmentsCompleted)
	}
	if report.Delta.SuppressionsAdded > 0 {
		fmt.Fprintf(&b, "Suppressions added remotely: %d.\n", report.Delta.SuppressionsAdded)
	}
	if len(report.Delta.AuthExpiredMailboxes) > 0 {
		fmt.Fprintf(&b, "Mailbox reconnect required: %s. Guide the user to reconnect before new sends.\n", strings.Join(report.Delta.AuthExpiredMailboxes, ", "))
	}

	return b.String()
}

func buildSkillRefreshBannerLine(staleSkills []session.StaleSkill) string {
	if len(staleSkills) == 0 {
		return ""
	}
	names := make([]string, 0, len(staleSkills))
	for i, item := range staleSkills {
		if i >= 3 {
			break
		}
		names = append(names, item.SkillName)
	}
	return fmt.Sprintf("Skills ready for refresh: %s", strings.Join(names, ", "))
}

func buildStrategicMemoryPromptContext(memories []session.StrategicMemory, staleSkills []session.StaleSkill) string {
	if len(memories) == 0 && len(staleSkills) == 0 {
		return ""
	}

	var b strings.Builder
	if len(memories) > 0 {
		b.WriteString("Strategic memory updates:\n")
		for _, memory := range memories {
			fmt.Fprintf(&b, "- %s", memory.Summary)
			if len(memory.AffectedSkills) > 0 {
				fmt.Fprintf(&b, " Affects: %s.", strings.Join(memory.AffectedSkills, ", "))
			}
			b.WriteString("\n")
		}
	}

	if len(staleSkills) > 0 {
		b.WriteString("Skills likely stale:\n")
		for _, item := range staleSkills {
			fmt.Fprintf(&b, "- %s: %s\n", item.SkillName, strings.Join(item.Reasons, "; "))
		}
		b.WriteString("If you refresh a skill, persist the new version with `nurge skills save <skill-name> --file .claude/skills/<skill-name>/SKILL.md`. Use `nurge skills stale --format json` for the full refresh list and `nurge memory list --format json` for the underlying strategic memory.\n")
	}

	return b.String()
}

func shortSyncError(err error) string {
	if err == nil {
		return ""
	}
	message := strings.TrimSpace(err.Error())
	if len(message) > 120 {
		return message[:117] + "..."
	}
	return message
}

func pluralSuffix(count int, forms ...string) string {
	if len(forms) == 2 {
		if count == 1 {
			return forms[0]
		}
		return forms[1]
	}
	if count == 1 {
		return ""
	}
	return "s"
}

// --- Auto-update ---

const (
	updateCacheFile   = ".nurge/update_check.json"
	updateCheckTTL    = 24 * time.Hour
	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
)

type updateCache struct {
	LatestVersion string `json:"latest_version"`
	CheckedAt     string `json:"checked_at"`
	UpdatedAt     string `json:"updated_at,omitempty"`
}

// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
// Returns a message for the banner, or empty string.
func checkAndAutoUpdate() string {
	// Read cache
	cache := readUpdateCache()

	// If checked recently, just report
	if cache != nil && cache.CheckedAt != "" {
		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
		if err == nil && time.Since(checkedAt) < updateCheckTTL {
			// Cache is fresh — check if we just updated
			if cache.UpdatedAt != "" {
				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
				if err == nil && time.Since(updatedAt) < 5*time.Minute {
					// Clear the updated flag for next time
					cache.UpdatedAt = ""
					writeUpdateCache(cache)
					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
				}
			}
			return ""
		}
	}

	// Check for latest version (with timeout)
	latest := fetchLatestVersion()
	if latest == "" {
		// Network failed — update cache timestamp so we don't retry immediately
		if cache == nil {
			cache = &updateCache{}
		}
		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
		writeUpdateCache(cache)
		return ""
	}

	// Save to cache
	if cache == nil {
		cache = &updateCache{}
	}
	cache.LatestVersion = latest
	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)

	// Compare: if current version matches latest, no update needed
	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
		writeUpdateCache(cache)
		return ""
	}

	// Different version — auto-update
	if runAutoUpdate() {
		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
		writeUpdateCache(cache)
		return fmt.Sprintf("Updating to %s...", latest)
	}

	writeUpdateCache(cache)
	return ""
}

func readUpdateCache() *updateCache {
	data, err := os.ReadFile(updateCacheFile)
	if err != nil {
		return nil
	}
	var c updateCache
	if err := json.Unmarshal(data, &c); err != nil {
		return nil
	}
	return &c
}

func writeUpdateCache(c *updateCache) {
	data, err := json.Marshal(c)
	if err != nil {
		return
	}
	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
	os.WriteFile(updateCacheFile, data, 0644)
}

// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
func fetchLatestVersion() string {
	client := &http.Client{Timeout: 3 * time.Second}
	resp, err := client.Get(githubReleasesURL)
	if err != nil {
		return ""
	}
	defer resp.Body.Close()

	if resp.StatusCode != 200 {
		return ""
	}

	var release struct {
		TagName string `json:"tag_name"`
	}
	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
		return ""
	}
	return release.TagName
}

// runAutoUpdate runs the install script in the background. Returns true if launched.
func runAutoUpdate() bool {
	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
	if err := cmd.Start(); err != nil {
		return false
	}
	// Don't wait — let it run in background
	go cmd.Wait()
	return true
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

func formatCount(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}

