535→func attemptSessionStartSync() *sessionSyncReport {
536→	report := &sessionSyncReport{}
537→
538→	if !db.Exists() {
539→		return report
540→	}
541→
542→	d, err := db.Open()
543→	if err != nil {
544→		report.Attempted = true
545→		report.Error = shortSyncError(err)
546→		return report
547→	}
548→	defer d.Close()
549→
550→	engine := loadSyncEngine(d)
551→	if engine == nil {
552→		return report
553→	}
554→
555→	report.Attempted = true
556→	pull, err := engine.Pull()
557→	if err != nil {
558→		report.Error = shortSyncError(err)
559→		return report
560→	}
561→
562→	report.RowsUpserted = pull.RowsUpserted
563→	report.TablesUpdated = pull.TablesUpdated
564→	report.PreviousVersion = pull.PreviousVersion
565→	report.CurrentVersion = pull.CurrentVersion
566→
567→	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
568→	if err == nil {
569→		report.Delta = delta
570→	}
571→	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
572→	if err == nil {
573→		for _, memory := range memories {
574→			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
575→				Category:       memory.Category,
576→				Summary:        memory.Summary,
577→				AffectedSkills: memory.AffectedSkills,
578→				Evidence:       memory.Evidence,
579→				Source:         memory.Source,
580→				SourceKey:      memory.SourceKey,
581→				Priority:       memory.Priority,
582→			})
583→		}
584→	}
585→
586→	return report
587→}
