613→func buildSyncBannerLine(report *sessionSyncReport) string {
614→	if report == nil || !report.Attempted {
615→		return ""
616→	}
617→	if report.Error != "" {
618→		return "Remote sync unavailable — using last local state"
619→	}
620→	if report.RowsUpserted == 0 {
621→		return ""
622→	}
623→
624→	parts := []string{}
625→	if report.Delta != nil {
626→		if report.Delta.TasksSent > 0 {
627→			parts = append(parts, fmt.Sprintf("%d follow-up%s sent", report.Delta.TasksSent, pluralSuffix(report.Delta.TasksSent)))
628→		}
629→		if report.Delta.RepliesNeedingAttention > 0 {
630→			parts = append(parts, fmt.Sprintf("%d repl%s need attention", report.Delta.RepliesNeedingAttention, pluralSuffix(report.Delta.RepliesNeedingAttention, "y", "ies")))
631→		}
632→		if report.Delta.TasksFailed > 0 {
633→			parts = append(parts, fmt.Sprintf("%d send failure%s", report.Delta.TasksFailed, pluralSuffix(report.Delta.TasksFailed)))
634→		}
635→		if len(report.Delta.AuthExpiredMailboxes) > 0 {
636→			parts = append(parts, fmt.Sprintf("%d mailbox reconnect%s needed", len(report.Delta.AuthExpiredMailboxes), pluralSuffix(len(report.Delta.AuthExpiredMailboxes))))
637→		}
638→	}
639→	if len(parts) == 0 {
640→		return fmt.Sprintf("Synced %d remote update%s", report.RowsUpserted, pluralSuffix(report.RowsUpserted))
641→	}
642→	return "While you were away: " + strings.Join(parts, " | ")
643→}
