661→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
662→		report.RowsUpserted,
663→		pluralSuffix(report.RowsUpserted),
664→		report.TablesUpdated,
665→		pluralSuffix(report.TablesUpdated),
