770→// --- Auto-update ---
771→
772→const (
773→	updateCacheFile   = ".nurge/update_check.json"
774→	updateCheckTTL    = 24 * time.Hour
775→	githubReleasesURL = "https://api.github.com/repos/usenurge/nurge/releases/latest"
776→)
777→
778→type updateCache struct {
779→	LatestVersion string `json:"latest_version"`
780→	CheckedAt     string `json:"checked_at"`
781→	UpdatedAt     string `json:"updated_at,omitempty"`
782→}
783→
784→// checkAndAutoUpdate checks for updates (cached, 24h TTL) and auto-updates if needed.
785→// Returns a message for the banner, or empty string.
786→func checkAndAutoUpdate() string {
787→	// Read cache
788→	cache := readUpdateCache()
789→
790→	// If checked recently, just report
791→	if cache != nil && cache.CheckedAt != "" {
792→		checkedAt, err := time.Parse(time.RFC3339, cache.CheckedAt)
793→		if err == nil && time.Since(checkedAt) < updateCheckTTL {
794→			// Cache is fresh — check if we just updated
795→			if cache.UpdatedAt != "" {
796→				updatedAt, err := time.Parse(time.RFC3339, cache.UpdatedAt)
797→				if err == nil && time.Since(updatedAt) < 5*time.Minute {
798→					// Clear the updated flag for next time
799→					cache.UpdatedAt = ""
800→					writeUpdateCache(cache)
801→					return fmt.Sprintf("Updated to %s", cache.LatestVersion)
802→				}
803→			}
804→			return ""
805→		}
806→	}
807→
808→	// Check for latest version (with timeout)
809→	latest := fetchLatestVersion()
810→	if latest == "" {
811→		// Network failed — update cache timestamp so we don't retry immediately
812→		if cache == nil {
813→			cache = &updateCache{}
814→		}
815→		cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
816→		writeUpdateCache(cache)
817→		return ""
818→	}
819→
820→	// Save to cache
821→	if cache == nil {
822→		cache = &updateCache{}
823→	}
824→	cache.LatestVersion = latest
825→	cache.CheckedAt = time.Now().UTC().Format(time.RFC3339)
826→
827→	// Compare: if current version matches latest, no update needed
828→	if buildVersion == latest || buildVersion == latest[1:] { // handle v prefix
829→		writeUpdateCache(cache)
830→		return ""
831→	}
832→
833→	// Different version — auto-update
834→	if runAutoUpdate() {
835→		cache.UpdatedAt = time.Now().UTC().Format(time.RFC3339)
836→		writeUpdateCache(cache)
837→		return fmt.Sprintf("Updating to %s...", latest)
838→	}
839→
840→	writeUpdateCache(cache)
841→	return ""
842→}
843→
844→func readUpdateCache() *updateCache {
845→	data, err := os.ReadFile(updateCacheFile)
846→	if err != nil {
847→		return nil
848→	}
849→	var c updateCache
850→	if err := json.Unmarshal(data, &c); err != nil {
851→		return nil
852→	}
853→	return &c
854→}
855→
856→func writeUpdateCache(c *updateCache) {
857→	data, err := json.Marshal(c)
858→	if err != nil {
859→		return
860→	}
861→	os.MkdirAll(filepath.Dir(updateCacheFile), 0755)
862→	os.WriteFile(updateCacheFile, data, 0644)
863→}
