865→// fetchLatestVersion gets the latest release tag from GitHub. 3s timeout.
866→func fetchLatestVersion() string {
867→	client := &http.Client{Timeout: 3 * time.Second}
868→	resp, err := client.Get(githubReleasesURL)
869→	if err != nil {
870→		return ""
871→	}
872→	defer resp.Body.Close()
873→
874→	if resp.StatusCode != 200 {
875→		return ""
876→	}
877→
878→	var release struct {
879→		TagName string `json:"tag_name"`
880→	}
881→	if err := json.NewDecoder(resp.Body).Decode(&release); err != nil {
882→		return ""
883→	}
884→	return release.TagName
885→}
