887→// runAutoUpdate runs the install script in the background. Returns true if launched.
888→func runAutoUpdate() bool {
889→	cmd := exec.Command("sh", "-c", "curl -fsSL https://install.nurge.sh | sh >/dev/null 2>&1")
890→	if err := cmd.Start(); err != nil {
891→		return false
892→	}
893→	// Don't wait — let it run in background
894→	go cmd.Wait()
895→	return true
896→}
