226→				MessageID:    sent.MessageID,
227→				SentAt:       sentAt,
228→			})
229→			if err != nil {
230→				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
231→			}
232→
233→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
234→			if nextTask != nil {
235→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
236→			}
237→		}
238→
239→		if task != nil {
240→			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
241→				TaskID:    task.ID,
242→				ThreadID:  sent.ThreadID,
243→				MessageID: sent.MessageID,
