216→// ListStaleSkills computes which tracked skills are likely stale relative to
217→// the current data volume, accumulated learnings, and strategic memory that
218→// landed after each skill's active version was saved.
219→func ListStaleSkills(db *sql.DB, limit int) ([]StaleSkill, error) {
220→	counts, err := CurrentSnapshotCounts(db)
221→	if err != nil {
222→		return nil, err
223→	}
224→
225→	activeVersions, err := listActiveSkillVersions(db)
226→	if err != nil {
227→		return nil, err
228→	}
229→	memories, err := ListStrategicMemory(db, 0)
230→	if err != nil {
231→		return nil, err
232→	}
233→
234→	entries := map[string]*StaleSkill{}
235→	getEntry := func(skillName string, active *activeSkillVersion) *StaleSkill {
236→		if existing, ok := entries[skillName]; ok {
237→			return existing
238→		}
239→		entry := &StaleSkill{SkillName: skillName}
240→		if active != nil {
241→			entry.ActiveVersion = active.Version
242→			entry.LastUpdated = active.CreatedAt
243→		}
244→		entries[skillName] = entry
245→		return entry
246→	}
247→
248→	for skillName, active := range activeVersions {
249→		entry := getEntry(skillName, &active)
250→		if emailDelta := counts.EmailCount - active.EmailCount; shouldFlagEmailDelta(active.EmailCount, emailDelta) {
251→			entry.EmailDelta = emailDelta
252→			entry.Reasons = append(entry.Reasons, fmt.Sprintf("%d new email%s since v%d", emailDelta, pluralize(emailDelta), active.Version))
253→		}
254→		if learningDelta := counts.LearningCount - active.LearningCount; shouldFlagLearningDelta(active.LearningCount, learningDelta) {
255→			entry.LearningDelta = learningDelta
256→			entry.Reasons = append(entry.Reasons, fmt.Sprintf("%d new learning%s since v%d", learningDelta, pluralize(learningDelta), active.Version))
257→		}
258→	}
259→
260→	for _, memory := range memories {
261→		for _, skillName := range memory.AffectedSkills {
262→			active, hasActive := activeVersions[skillName]
263→			if hasActive && !happenedAfter(memory.LastSeenAt, active.CreatedAt) {
264→				continue
265→			}
266→			entry := getEntry(skillName, activePtr(hasActive, active))
267→			entry.StrategicUpdateCount++
268→			entry.StrategicCategories = uniqueSortedStrings(append(entry.StrategicCategories, memory.Category))
269→		}
270→	}
271→
272→	var stale []StaleSkill
273→	for _, entry := range entries {
274→		if entry.StrategicUpdateCount > 0 {
275→			if entry.ActiveVersion == 0 {
276→				entry.Reasons = append(entry.Reasons, "new strategic memory exists but the skill has no tracked version yet")
277→			} else {
278→				entry.Reasons = append(
279→					entry.Reasons,
280→					fmt.Sprintf(
281→						"%d strategic update%s since v%d (%s)",
282→						entry.StrategicUpdateCount,
283→						pluralize(entry.StrategicUpdateCount),
284→						entry.ActiveVersion,
285→						strings.Join(prettyCategories(entry.StrategicCategories), ", "),
286→					),
287→				)
288→			}
289→		}
290→		if len(entry.Reasons) == 0 {
291→			continue
292→		}
293→		sort.Strings(entry.Reasons)
294→		stale = append(stale, *entry)
295→	}
296→
297→	sort.Slice(stale, func(i, j int) bool {
298→		if stale[i].StrategicUpdateCount != stale[j].StrategicUpdateCount {
299→			return stale[i].StrategicUpdateCount > stale[j].StrategicUpdateCount
300→		}
301→		if stale[i].LearningDelta != stale[j].LearningDelta {
302→			return stale[i].LearningDelta > stale[j].LearningDelta
303→		}
304→		if stale[i].EmailDelta != stale[j].EmailDelta {
305→			return stale[i].EmailDelta > stale[j].EmailDelta
306→		}
307→		return stale[i].SkillName < stale[j].SkillName
308→	})
309→
310→	if limit > 0 && len(stale) > limit {
311→		stale = stale[:limit]
312→	}
313→	return stale, nil
314→}
