379→func parseSQLiteTime(value string) (time.Time, bool) {
380→	for _, layout := range []string{"2006-01-02 15:04:05", time.RFC3339, time.RFC3339Nano} {
381→		parsed, err := time.Parse(layout, value)
382→		if err == nil {
383→			return parsed, true
384→		}
385→	}
386→	return time.Time{}, false
387→}
