package session

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
)

// Learning represents a single insight captured from a Claude Code session.
type Learning struct {
	ID            int    `json:"id"`
	Type          string `json:"type"`
	Content       string `json:"content"`
	SourceSession string `json:"source_session,omitempty"`
	CreatedAt     string `json:"created_at"`
}

// SkillVersion represents a versioned snapshot of a skill.
type SkillVersion struct {
	ID            int    `json:"id"`
	SkillName     string `json:"skill_name"`
	Version       int    `json:"version"`
	Content       string `json:"content"`
	EmailCount    int    `json:"email_count"`
	LearningCount int    `json:"learning_count"`
	Active        bool   `json:"active"`
	CreatedAt     string `json:"created_at"`
}

// SkillSummary is a brief view of a skill with its current version.
type SkillSummary struct {
	SkillName     string `json:"skill_name"`
	ActiveVersion int    `json:"active_version"`
	TotalVersions int    `json:"total_versions"`
	LastUpdated   string `json:"last_updated"`
}

// SaveLearning inserts a new learning into the database.
func SaveLearning(db *sql.DB, typ, content, sourceSession string) (int64, error) {
	result, err := db.Exec(
		`INSERT INTO learnings (type, content, source_session) VALUES (?, ?, ?)`,
		typ, content, sourceSession,
	)
	if err != nil {
		return 0, fmt.Errorf("saving learning: %w", err)
	}
	return result.LastInsertId()
}

// ListLearnings returns all learnings, optionally filtered by type.
func ListLearnings(db *sql.DB, filterType string) ([]Learning, error) {
	var rows *sql.Rows
	var err error

	if filterType != "" {
		rows, err = db.Query(
			`SELECT id, type, content, source_session, created_at FROM learnings WHERE type = ? ORDER BY created_at DESC`,
			filterType,
		)
	} else {
		rows, err = db.Query(
			`SELECT id, type, content, source_session, created_at FROM learnings ORDER BY created_at DESC`,
		)
	}
	if err != nil {
		return nil, fmt.Errorf("listing learnings: %w", err)
	}
	defer rows.Close()

	var learnings []Learning
	for rows.Next() {
		var l Learning
		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
			return nil, fmt.Errorf("scanning learning: %w", err)
		}
		learnings = append(learnings, l)
	}
	return learnings, rows.Err()
}

// SaveSkillVersion saves a new version of a skill. It deactivates all previous
// versions and marks the new one as active.
func SaveSkillVersion(db *sql.DB, skillName, content string, emailCount, learningCount int) (int, error) {
	tx, err := db.Begin()
	if err != nil {
		return 0, fmt.Errorf("beginning transaction: %w", err)
	}
	defer tx.Rollback()

	// Get next version number
	var maxVersion sql.NullInt64
	err = tx.QueryRow(
		`SELECT MAX(version) FROM skill_versions WHERE skill_name = ?`,
		skillName,
	).Scan(&maxVersion)
	if err != nil {
		return 0, fmt.Errorf("getting max version: %w", err)
	}

	nextVersion := 1
	if maxVersion.Valid {
		nextVersion = int(maxVersion.Int64) + 1
	}

	// Deactivate all previous versions
	_, err = tx.Exec(
		`UPDATE skill_versions SET active = 0, updated_at = datetime('now') WHERE skill_name = ?`,
		skillName,
	)
	if err != nil {
		return 0, fmt.Errorf("deactivating versions: %w", err)
	}

	// Insert new version as active
	_, err = tx.Exec(
		`INSERT INTO skill_versions (skill_name, version, content, email_count, learning_count, active) VALUES (?, ?, ?, ?, ?, 1)`,
		skillName, nextVersion, content, emailCount, learningCount,
	)
	if err != nil {
		return 0, fmt.Errorf("inserting version: %w", err)
	}

	if err := tx.Commit(); err != nil {
		return 0, fmt.Errorf("committing transaction: %w", err)
	}
	if err := writeSkillToDisk(skillName, content); err != nil {
		return 0, err
	}

	return nextVersion, nil
}

// ListSkills returns a summary of all skills with their active version info.
func ListSkills(db *sql.DB) ([]SkillSummary, error) {
	rows, err := db.Query(`
		SELECT
			sv.skill_name,
			COALESCE(active.version, 0) AS active_version,
			COUNT(*) AS total_versions,
			MAX(sv.created_at) AS last_updated
		FROM skill_versions sv
		LEFT JOIN skill_versions active
			ON active.skill_name = sv.skill_name AND active.active = 1
		GROUP BY sv.skill_name
		ORDER BY sv.skill_name
	`)
	if err != nil {
		return nil, fmt.Errorf("listing skills: %w", err)
	}
	defer rows.Close()

	var skills []SkillSummary
	for rows.Next() {
		var s SkillSummary
		if err := rows.Scan(&s.SkillName, &s.ActiveVersion, &s.TotalVersions, &s.LastUpdated); err != nil {
			return nil, fmt.Errorf("scanning skill: %w", err)
		}
		skills = append(skills, s)
	}
	return skills, rows.Err()
}

// SkillHistory returns all versions of a skill, newest first.
func SkillHistory(db *sql.DB, skillName string) ([]SkillVersion, error) {
	rows, err := db.Query(
		`SELECT id, skill_name, version, content, email_count, learning_count, active, created_at
		 FROM skill_versions WHERE skill_name = ? ORDER BY version DESC`,
		skillName,
	)
	if err != nil {
		return nil, fmt.Errorf("getting skill history: %w", err)
	}
	defer rows.Close()

	var versions []SkillVersion
	for rows.Next() {
		var v SkillVersion
		if err := rows.Scan(&v.ID, &v.SkillName, &v.Version, &v.Content, &v.EmailCount, &v.LearningCount, &v.Active, &v.CreatedAt); err != nil {
			return nil, fmt.Errorf("scanning version: %w", err)
		}
		versions = append(versions, v)
	}
	return versions, rows.Err()
}

// RollbackSkill restores a previous version of a skill by marking it as active
// and writing its content to disk.
func RollbackSkill(db *sql.DB, skillName string, version int) error {
	tx, err := db.Begin()
	if err != nil {
		return fmt.Errorf("beginning transaction: %w", err)
	}
	defer tx.Rollback()

	// Verify the version exists
	var content string
	err = tx.QueryRow(
		`SELECT content FROM skill_versions WHERE skill_name = ? AND version = ?`,
		skillName, version,
	).Scan(&content)
	if err == sql.ErrNoRows {
		return fmt.Errorf("version %d not found for skill %s", version, skillName)
	}
	if err != nil {
		return fmt.Errorf("reading version: %w", err)
	}

	// Deactivate all versions
	_, err = tx.Exec(
		`UPDATE skill_versions SET active = 0, updated_at = datetime('now') WHERE skill_name = ?`,
		skillName,
	)
	if err != nil {
		return fmt.Errorf("deactivating versions: %w", err)
	}

	// Activate the target version
	_, err = tx.Exec(
		`UPDATE skill_versions SET active = 1, updated_at = datetime('now') WHERE skill_name = ? AND version = ?`,
		skillName, version,
	)
	if err != nil {
		return fmt.Errorf("activating version: %w", err)
	}

	if err := tx.Commit(); err != nil {
		return fmt.Errorf("committing transaction: %w", err)
	}

	return writeSkillToDisk(skillName, content)
}

// PrintJSON marshals v to JSON and writes it to stdout.
func PrintJSON(v any) error {
	enc := json.NewEncoder(os.Stdout)
	enc.SetIndent("", "  ")
	return enc.Encode(v)
}

func writeSkillToDisk(skillName, content string) error {
	skillDir := filepath.Join(".claude", "skills", skillName)
	if err := os.MkdirAll(skillDir, 0755); err != nil {
		return fmt.Errorf("creating skill directory: %w", err)
	}
	skillPath := filepath.Join(skillDir, "SKILL.md")
	if err := os.WriteFile(skillPath, []byte(content), 0644); err != nil {
		return fmt.Errorf("writing skill file: %w", err)
	}
	return nil
}

