  1→package sync
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"time"
  8→
  9→	"github.com/usenurge/nurgesh/internal/account"
 10→)
 11→
 12→// executionTables are tables where Convex is authoritative.
 13→// Pull direction: Convex → SQLite.
 14→var executionTables = []string{
 15→	"emails",
 16→	"mailboxes",
 17→	"mailbox_send_events",
 18→	"sequence_enrollments",
 19→	"follow_up_tasks",
 20→	"suppressions",
 21→	"reply_events",
 22→	"sequence_drafts",
 23→}
 24→
 25→// localTables are tables where SQLite is authoritative.
 26→// Push direction: SQLite → Convex.
 27→var localTables = []string{
 28→	"contacts",
 29→	"learnings",
 30→	"skill_versions",
 31→	"deals",
 32→}
 33→
 34→const batchSize = 500
 35→
 36→// SyncState tracks the last sync position per direction.
 37→type SyncState struct {
 38→	LastPullVersion int64  `json:"last_pull_version"`
 39→	LastPushAt      string `json:"last_push_at"`
 40→}
 41→
 42→// Engine handles bidirectional sync between SQLite and Convex.
 43→type Engine struct {
 44→	db     *sql.DB
 45→	client *account.ConvexClient
 46→	token  string
 47→}
 48→
 49→// NewEngine creates a sync engine.
 50→func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
 51→	return &Engine{db: db, client: client, token: token}
 52→}
 53→
 54→// PullResult contains stats from a pull operation.
 55→type PullResult struct {
 56→	PreviousVersion int64
 57→	CurrentVersion  int64
 58→	TablesUpdated   int
 59→	RowsUpserted    int
 60→	TableCounts     map[string]int
 61→}
 62→
 63→// PushResult contains stats from a push operation.
 64→type PushResult struct {
 65→	TablesScanned int
 66→	RowsPushed    int
 67→}
 68→
 69→// SyncResult contains stats from a full sync (pull + push).
 70→type SyncResult struct {
 71→	Pull PullResult
 72→	Push PushResult
 73→}
 74→
 75→// Sync performs a full sync: pull execution state, then push local state.
 76→func (e *Engine) Sync() (*SyncResult, error) {
 77→	pullResult, err := e.Pull()
 78→	if err != nil {
 79→		return nil, fmt.Errorf("pull failed: %w", err)
 80→	}
 81→
 82→	pushResult, err := e.Push()
 83→	if err != nil {
 84→		return nil, fmt.Errorf("push failed: %w", err)
 85→	}
 86→
 87→	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
 88→}
 89→
 90→// Pull fetches execution state from Convex and upserts into SQLite.
 91→func (e *Engine) Pull() (*PullResult, error) {
 92→	state, err := e.loadSyncState()
 93→	if err != nil {
 94→		return nil, fmt.Errorf("loading sync state: %w", err)
 95→	}
 96→	previousVersion := state.LastPullVersion
 97→
 98→	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
 99→	if err != nil {
100→		return nil, fmt.Errorf("pulling from Convex: %w", err)
101→	}
102→
103→	result := &PullResult{
104→		PreviousVersion: previousVersion,
105→		CurrentVersion:  previousVersion,
106→		TableCounts:     make(map[string]int),
107→	}
108→	tablesUpdated := map[string]bool{}
109→
110→	for _, row := range resp.Rows {
111→		if err := e.upsertRow(row); err != nil {
112→			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
113→		}
114→		result.RowsUpserted++
115→		tablesUpdated[row.Table] = true
116→		result.TableCounts[row.Table]++
117→	}
118→	result.TablesUpdated = len(tablesUpdated)
119→
120→	if resp.SyncVersion > state.LastPullVersion {
121→		state.LastPullVersion = resp.SyncVersion
122→		result.CurrentVersion = resp.SyncVersion
123→		if err := e.saveSyncState(state); err != nil {
124→			return nil, fmt.Errorf("saving sync state: %w", err)
125→		}
126→	}
127→
128→	return result, nil
129→}
130→
131→// Push sends local state changes to Convex.
132→func (e *Engine) Push() (*PushResult, error) {
133→	state, err := e.loadSyncState()
134→	if err != nil {
135→		return nil, fmt.Errorf("loading sync state: %w", err)
136→	}
137→
138→	result := &PushResult{}
139→	var allRows []account.SyncRow
140→
141→	for _, table := range localTables {
142→		rows, err := e.changedLocalRows(table, state.LastPushAt)
143→		if err != nil {
144→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
145→		}
146→		allRows = append(allRows, rows...)
147→		result.TablesScanned++
148→	}
149→
150→	// Also push email classifications (local authority for the classification field)
151→	classRows, err := e.changedEmailClassifications(state.LastPushAt)
152→	if err != nil {
153→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
154→	}
155→	allRows = append(allRows, classRows...)
156→
157→	if len(allRows) == 0 {
158→		return result, nil
159→	}
160→
161→	// Push in batches
162→	for i := 0; i < len(allRows); i += batchSize {
163→		end := i + batchSize
164→		if end > len(allRows) {
165→			end = len(allRows)
166→		}
167→		batch := allRows[i:end]
168→
169→		resp, err := e.client.PushLocalState(e.token, batch)
170→		if err != nil {
171→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
172→		}
173→
174→		// Update local sync_version from server response
175→		for id, version := range resp.Versions {
176→			for _, row := range batch {
177→				if row.ID == id {
178→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
179→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
180→					}
181→					break
182→				}
183→			}
184→		}
185→		result.RowsPushed += len(batch)
186→	}
187→
188→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
189→	if err := e.saveSyncState(state); err != nil {
190→		return nil, fmt.Errorf("saving sync state: %w", err)
191→	}
192→
193→	return result, nil
194→}
195→
196→// upsertRow writes a Convex row into the local SQLite table.
197→func (e *Engine) upsertRow(row account.SyncRow) error {
198→	if len(row.Data) == 0 {
199→		return nil
200→	}
201→
202→	columns := []string{"id"}
203→	placeholders := []string{"?"}
204→	values := []any{row.ID}
205→	updateParts := []string{}
206→
207→	for col, val := range row.Data {
208→		columns = append(columns, col)
209→		placeholders = append(placeholders, "?")
210→		values = append(values, val)
211→		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
212→	}
213→
214→	// Always set sync_version
215→	columns = append(columns, "sync_version")
216→	placeholders = append(placeholders, "?")
217→	values = append(values, row.Version)
218→	updateParts = append(updateParts, "sync_version = excluded.sync_version")
219→
220→	query := fmt.Sprintf(
221→		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
222→		row.Table,
223→		joinStrings(columns, ", "),
224→		joinStrings(placeholders, ", "),
225→		joinStrings(updateParts, ", "),
226→	)
227→
228→	_, err := e.db.Exec(query, values...)
229→	return err
230→}
231→
232→// changedLocalRows returns rows from a local-state table changed since lastPushAt.
233→func (e *Engine) changedLocalRows(table, lastPushAt string) ([]account.SyncRow, error) {
234→	var rows []account.SyncRow
235→
236→	query := fmt.Sprintf("SELECT * FROM %s", table)
237→	args := []any{}
238→	if lastPushAt != "" {
239→		query += " WHERE updated_at > ?"
240→		args = append(args, lastPushAt)
241→	}
242→
243→	sqlRows, err := e.db.Query(query, args...)
244→	if err != nil {
245→		return nil, err
246→	}
247→	defer sqlRows.Close()
248→
249→	cols, err := sqlRows.Columns()
250→	if err != nil {
251→		return nil, err
252→	}
253→
254→	for sqlRows.Next() {
255→		values := make([]any, len(cols))
256→		ptrs := make([]any, len(cols))
257→		for i := range values {
258→			ptrs[i] = &values[i]
259→		}
260→		if err := sqlRows.Scan(ptrs...); err != nil {
261→			return nil, err
262→		}
263→
264→		data := map[string]any{}
265→		var id string
266→		for i, col := range cols {
267→			if col == "id" {
268→				id = fmt.Sprintf("%v", values[i])
269→			}
270→			if col == "sync_version" {
271→				continue // don't push sync_version back
272→			}
273→			data[col] = values[i]
274→		}
275→
276→		rows = append(rows, account.SyncRow{
277→			Table: table,
278→			ID:    id,
279→			Data:  data,
280→		})
281→	}
282→
283→	return rows, sqlRows.Err()
284→}
285→
286→// changedEmailClassifications returns emails with updated classifications.
287→func (e *Engine) changedEmailClassifications(lastPushAt string) ([]account.SyncRow, error) {
288→	query := `SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`
289→	args := []any{}
