package sync

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"time"

	"github.com/usenurge/nurgesh/internal/account"
)

// executionTables are tables where Convex is authoritative.
// Pull direction: Convex → SQLite.
var executionTables = []string{
	"emails",
	"mailboxes",
	"mailbox_send_events",
	"sequence_enrollments",
	"follow_up_tasks",
	"suppressions",
	"reply_events",
	"sequence_drafts",
}

// localTables are tables where SQLite is authoritative.
// Push direction: SQLite → Convex.
var localTables = []string{
	"contacts",
	"learnings",
	"skill_versions",
	"deals",
}

const batchSize = 500

// SyncState tracks the last sync position per direction.
type SyncState struct {
	LastPullVersion int64  `json:"last_pull_version"`
	LastPushAt      string `json:"last_push_at"`
}

// Engine handles bidirectional sync between SQLite and Convex.
type Engine struct {
	db     *sql.DB
	client *account.ConvexClient
	token  string
}

// NewEngine creates a sync engine.
func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
	return &Engine{db: db, client: client, token: token}
}

// PullResult contains stats from a pull operation.
type PullResult struct {
	PreviousVersion int64
	CurrentVersion  int64
	TablesUpdated   int
	RowsUpserted    int
	TableCounts     map[string]int
}

// PushResult contains stats from a push operation.
type PushResult struct {
	TablesScanned int
	RowsPushed    int
}

// SyncResult contains stats from a full sync (pull + push).
type SyncResult struct {
	Pull PullResult
	Push PushResult
}

// Sync performs a full sync: pull execution state, then push local state.
func (e *Engine) Sync() (*SyncResult, error) {
	pullResult, err := e.Pull()
	if err != nil {
		return nil, fmt.Errorf("pull failed: %w", err)
	}

	pushResult, err := e.Push()
	if err != nil {
		return nil, fmt.Errorf("push failed: %w", err)
	}

	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
}

// Pull fetches execution state from Convex and upserts into SQLite.
func (e *Engine) Pull() (*PullResult, error) {
	state, err := e.loadSyncState()
	if err != nil {
		return nil, fmt.Errorf("loading sync state: %w", err)
	}
	previousVersion := state.LastPullVersion

	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
	if err != nil {
		return nil, fmt.Errorf("pulling from Convex: %w", err)
	}

	result := &PullResult{
		PreviousVersion: previousVersion,
		CurrentVersion:  previousVersion,
		TableCounts:     make(map[string]int),
	}
	tablesUpdated := map[string]bool{}

	for _, row := range resp.Rows {
		if err := e.upsertRow(row); err != nil {
			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
		}
		result.RowsUpserted++
		tablesUpdated[row.Table] = true
		result.TableCounts[row.Table]++
	}
	result.TablesUpdated = len(tablesUpdated)

	if resp.SyncVersion > state.LastPullVersion {
		state.LastPullVersion = resp.SyncVersion
		result.CurrentVersion = resp.SyncVersion
		if err := e.saveSyncState(state); err != nil {
			return nil, fmt.Errorf("saving sync state: %w", err)
		}
	}

	return result, nil
}

// Push sends local state changes to Convex.
func (e *Engine) Push() (*PushResult, error) {
	state, err := e.loadSyncState()
	if err != nil {
		return nil, fmt.Errorf("loading sync state: %w", err)
	}

	result := &PushResult{}
	var allRows []account.SyncRow

	for _, table := range localTables {
		rows, err := e.changedLocalRows(table, state.LastPushAt)
		if err != nil {
			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
		}
		allRows = append(allRows, rows...)
		result.TablesScanned++
	}

	// Also push email classifications (local authority for the classification field)
	classRows, err := e.changedEmailClassifications(state.LastPushAt)
	if err != nil {
		return nil, fmt.Errorf("reading changed email classifications: %w", err)
	}
	allRows = append(allRows, classRows...)

	if len(allRows) == 0 {
		return result, nil
	}

	// Push in batches
	for i := 0; i < len(allRows); i += batchSize {
		end := i + batchSize
		if end > len(allRows) {
			end = len(allRows)
		}
		batch := allRows[i:end]

		resp, err := e.client.PushLocalState(e.token, batch)
		if err != nil {
			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
