	values := []any{row.ID}
	updateParts := []string{}

	for col, val := range row.Data {
		columns = append(columns, col)
		placeholders = append(placeholders, "?")
		values = append(values, val)
		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
	}

	// Always set sync_version
	columns = append(columns, "sync_version")
	placeholders = append(placeholders, "?")
	values = append(values, row.Version)
	updateParts = append(updateParts, "sync_version = excluded.sync_version")

	query := fmt.Sprintf(
		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
		row.Table,
		joinStrings(columns, ", "),
		joinStrings(placeholders, ", "),
		joinStrings(updateParts, ", "),
	)

	_, err := e.db.Exec(query, values...)
	return err
