// Emails lack updated_at so all are pushed each time — idempotent on Convex side.
func (e *Engine) changedEmailClassifications() ([]account.SyncRow, error) {
	sqlRows, err := e.db.Query(`SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`)
	if err != nil {
		return nil, err
	}
	defer sqlRows.Close()

	var rows []account.SyncRow
	for sqlRows.Next() {
		var id, class, classifiedBy string
		var confidence float64
		if err := sqlRows.Scan(&id, &class, &confidence, &classifiedBy); err != nil {
			return nil, err
		}

		rows = append(rows, account.SyncRow{
			Table: "emails",
			ID:    id,
			Data: map[string]any{
				"class":            class,
				"class_confidence": confidence,
				"classified_by":    classifiedBy,
			},
		})
	}

	return rows, sqlRows.Err()
}

// updateSyncVersion sets the sync_version for a specific row.
func (e *Engine) updateSyncVersion(table, id string, version int64) error {
	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
	_, err := e.db.Exec(query, version, id)
	return err
}

const syncStateKey = "_sync_state"

// loadSyncState reads the sync cursor from a local config-like store.
func (e *Engine) loadSyncState() (*SyncState, error) {
	// Store sync state in a simple key-value row in connectors table (reusing existing table)
	var data string
	err := e.db.QueryRow(
		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
	).Scan(&data)
	if err == sql.ErrNoRows {
		return &SyncState{}, nil
	}
	if err != nil {
		return nil, err
	}

	var state SyncState
	if err := json.Unmarshal([]byte(data), &state); err != nil {
		return &SyncState{}, nil
	}
	return &state, nil
}

// saveSyncState persists the sync cursor.
func (e *Engine) saveSyncState(state *SyncState) error {
	data, err := json.Marshal(state)
	if err != nil {
		return err
	}

	_, err = e.db.Exec(`
		INSERT INTO connectors (id, type, sync_cursor)
		VALUES (?, 'sync', ?)
		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
		syncStateKey, string(data),
	)
	return err
}

func strings.Join(parts []string, sep string) string {
	result := ""
	for i, p := range parts {
		if i > 0 {
			result += sep
		}
		result += p
	}
	return result
}

