534→func attemptSessionStartSync() *sessionSyncReport {
535→	report := &sessionSyncReport{}
536→
537→	if !db.Exists() {
538→		return report
539→	}
540→
541→	d, err := db.Open()
542→	if err != nil {
543→		report.Attempted = true
544→		report.Error = shortSyncError(err)
545→		return report
546→	}
547→	defer d.Close()
548→
549→	engine := loadSyncEngine(d)
550→	if engine == nil {
551→		return report
552→	}
553→
554→	report.Attempted = true
555→	pull, err := engine.Pull()
556→	if err != nil {
557→		report.Error = shortSyncError(err)
558→		return report
559→	}
560→
561→	report.RowsUpserted = pull.RowsUpserted
562→	report.TablesUpdated = pull.TablesUpdated
563→	report.PreviousVersion = pull.PreviousVersion
564→	report.CurrentVersion = pull.CurrentVersion
565→
566→	delta, err := engine.SummarizeExecutionDelta(pull.PreviousVersion, pull.CurrentVersion)
567→	if err == nil {
568→		report.Delta = delta
569→	}
570→	memories, err := engine.DistillExecutionMemory(pull.PreviousVersion, pull.CurrentVersion)
571→	if err == nil {
572→		for _, memory := range memories {
573→			_ = session.SaveStrategicMemory(d, session.StrategicMemoryInput{
574→				Category:       memory.Category,
575→				Summary:        memory.Summary,
576→				AffectedSkills: memory.AffectedSkills,
577→				Evidence:       memory.Evidence,
578→				Source:         memory.Source,
579→				SourceKey:      memory.SourceKey,
580→				Priority:       memory.Priority,
581→			})
582→		}
583→	}
584→
585→	return report
586→}
