644→func buildSyncPromptContext(report *sessionSyncReport) string {
645→	if report == nil || !report.Attempted {
646→		return ""
647→	}
648→
649→	var b strings.Builder
650→	if report.Error != "" {
651→		fmt.Fprintf(&b, "Remote sync status: unavailable (%s). Work from local state and avoid assuming cloud execution has fully caught up.\n", report.Error)
