660→	fmt.Fprintf(&b, "Remote sync status: pulled %d row%s across %d table%s.\n",
661→		report.RowsUpserted,
662→		pluralSuffix(report.RowsUpserted),
663→		report.TablesUpdated,
664→		pluralSuffix(report.TablesUpdated),
665→	)
666→
667→	if report.Delta == nil {
