129→
130→		if err := sequence.CanSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
131→			return err
132→		}
133→
134→		srv, err := email.NewClient("")
135→		if err != nil {
136→			return fmt.Errorf("connecting to Gmail: %w", err)
137→		}
138→		fromAddress := strings.TrimSpace(selectedMailbox.TransportEmail)
139→		if fromAddress == "" {
140→			fromAddress = strings.TrimSpace(selectedMailbox.Email)
141→		}
142→
143→		var threadID string
144→		if task != nil {
145→			threadID = task.ThreadID
146→		}
147→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
148→			To:       sendTo,
149→			Cc:       sendCc,
150→			Subject:  sendSubject,
151→			Body:     sendBody,
152→			ThreadID: threadID,
153→		})
154→		if err != nil {
155→			if task != nil {
156→				_ = sequence.MarkTaskAttempt(d, task.ID, sentAt, err)
157→				_ = sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusFailed, "", "", err.Error())
158→				_ = sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
159→					MailboxID:    selectedMailbox.ID,
160→					EnrollmentID: task.EnrollmentID,
161→					TaskID:       task.ID,
162→					ContactEmail: sendTo,
163→					SendType:     effectiveSendType,
164→					Status:       sequence.TaskSendStatusFailed,
165→					Subject:      sendSubject,
166→					Error:        err.Error(),
167→					AttemptedAt:  sentAt,
168→				})
169→			}
170→			return err
171→		}
172→
173→		if err := sequence.RecordSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
174→			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
175→		}
176→		if err := email.StoreEmail(d, &email.RawMessage{
177→			ID:        sent.MessageID,
178→			Source:    "gmail",
179→			Direction: "outbound",
180→			ThreadID:  sent.ThreadID,
181→			Subject:   sendSubject,
182→			FromEmail: fromAddress,
183→			ToEmails:  recipientsJSON(sendTo),
184→			CcEmails:  recipientsJSON(sendCc),
185→			Date:      sentAt.UTC().Format(time.RFC3339),
186→			Labels:    `["SENT"]`,
187→		}); err != nil {
188→			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
189→		}
190→		if task != nil {
191→			if err := sequence.UpdateTaskSendState(d, task.ID, sequence.TaskSendStatusSent, sent.MessageID, "", ""); err != nil {
192→				return fmt.Errorf("email sent (message ID: %s) but failed to update send state for task %s: %w", sent.MessageID, task.ID, err)
193→			}
194→		}
195→		var enrollmentID, taskID string
196→		if task != nil {
197→			enrollmentID = task.EnrollmentID
198→			taskID = task.ID
199→		}
200→		if err := sequence.LogSendAttempt(d, sequence.SendAttemptOptions{
201→			MailboxID:    selectedMailbox.ID,
202→			EnrollmentID: enrollmentID,
203→			TaskID:       taskID,
204→			ContactEmail: sendTo,
205→			SendType:     effectiveSendType,
206→			Status:       sequence.TaskSendStatusSent,
207→			Subject:      sendSubject,
208→			MessageID:    sent.MessageID,
209→			AttemptedAt:  sentAt,
210→		}); err != nil {
211→			return fmt.Errorf("email sent (message ID: %s) but failed to log send attempt: %w", sent.MessageID, err)
212→		}
213→
214→		fmt.Printf("  ✓ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
215→
216→		if sendSequence != "" {
217→			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
218→				SequenceName: sendSequence,
219→				CampaignName: sendCampaign,
220→				MailboxID:    selectedMailbox.ID,
221→				ContactEmail: sendTo,
222→				ContactName:  sendContactName,
223→				Subject:      sendSubject,
224→				InitialBody:  sendBody,
225→				ThreadID:     sent.ThreadID,
226→				MessageID:    sent.MessageID,
227→				SentAt:       sentAt,
228→			})
229→			if err != nil {
230→				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
231→			}
232→
233→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
234→			if nextTask != nil {
235→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
236→			}
237→		}
238→
239→		if task != nil {
240→			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
241→				TaskID:    task.ID,
242→				ThreadID:  sent.ThreadID,
243→				MessageID: sent.MessageID,
244→				MailboxID: selectedMailbox.ID,
245→				SentAt:    sentAt,
246→			})
247→			if err != nil {
248→				return fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, task.ID, err)
249→			}
250→			if nextTask != nil {
251→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
252→			} else {
253→				fmt.Println("  ↳ Sequence completed")
254→			}
255→		}
256→
257→		return nil
258→	},
259→}
