278→func recipientsJSON(raw string) string {
279→	raw = strings.TrimSpace(raw)
280→	if raw == "" {
281→		return "[]"
282→	}
283→	parts := strings.Split(raw, ",")
284→	recipients := make([]string, 0, len(parts))
285→	for _, part := range parts {
