241→// openSessionDB reads hook stdin, opens the DB, and ensures session tables.
242→// Returns (nil, nil, nil) when the hook should silently no-op.
243→func openSessionDB() (*sql.DB, *session.HookInput, error) {
244→	input, err := session.ReadStdin()
245→	if err != nil || input == nil || input.SessionID == "" {
246→		return nil, nil, nil
247→	}
248→	if !db.Exists() {
249→		return nil, nil, nil
250→	}
251→	d, err := db.Open()
252→	if err != nil {
253→		return nil, nil, nil
254→	}
255→	return d, input, nil
256→}
