  1→package sync
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→	"time"
  9→
 10→	"github.com/usenurge/nurgesh/internal/account"
 11→)
 12→
 13→// executionTables are tables where Convex is authoritative.
 14→// Pull direction: Convex → SQLite.
 15→var executionTables = []string{
 16→	"emails",
 17→	"mailboxes",
 18→	"mailbox_send_events",
 19→	"sequence_enrollments",
 20→	"follow_up_tasks",
 21→	"suppressions",
 22→	"reply_events",
 23→	"sequence_drafts",
 24→}
 25→
 26→// localTables are tables where SQLite is authoritative.
 27→// Push direction: SQLite → Convex.
 28→var localTables = []string{
 29→	"contacts",
 30→	"learnings",
 31→	"skill_versions",
 32→	"deals",
 33→}
 34→
 35→const batchSize = 500
 36→
 37→// SyncState tracks the last sync position per direction.
 38→type SyncState struct {
 39→	LastPullVersion int64  `json:"last_pull_version"`
 40→	LastPushAt      string `json:"last_push_at"`
 41→}
 42→
 43→// Engine handles bidirectional sync between SQLite and Convex.
 44→type Engine struct {
 45→	db     *sql.DB
 46→	client *account.ConvexClient
 47→	token  string
 48→}
 49→
 50→// NewEngine creates a sync engine.
 51→func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
 52→	return &Engine{db: db, client: client, token: token}
 53→}
 54→
 55→// PullResult contains stats from a pull operation.
 56→type PullResult struct {
 57→	PreviousVersion int64
 58→	CurrentVersion  int64
 59→	TablesUpdated   int
 60→	RowsUpserted    int
 61→	TableCounts     map[string]int
 62→}
 63→
 64→// PushResult contains stats from a push operation.
 65→type PushResult struct {
 66→	TablesScanned int
 67→	RowsPushed    int
 68→}
 69→
 70→// SyncResult contains stats from a full sync (pull + push).
 71→type SyncResult struct {
 72→	Pull PullResult
 73→	Push PushResult
 74→}
 75→
 76→// Sync performs a full sync: pull execution state, then push local state.
 77→func (e *Engine) Sync() (*SyncResult, error) {
 78→	pullResult, err := e.Pull()
 79→	if err != nil {
 80→		return nil, fmt.Errorf("pull failed: %w", err)
 81→	}
 82→
 83→	pushResult, err := e.Push()
 84→	if err != nil {
 85→		return nil, fmt.Errorf("push failed: %w", err)
 86→	}
 87→
 88→	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
 89→}
 90→
 91→// Pull fetches execution state from Convex and upserts into SQLite.
 92→func (e *Engine) Pull() (*PullResult, error) {
 93→	state, err := e.loadSyncState()
 94→	if err != nil {
 95→		return nil, fmt.Errorf("loading sync state: %w", err)
 96→	}
 97→	previousVersion := state.LastPullVersion
 98→
 99→	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
100→	if err != nil {
101→		return nil, fmt.Errorf("pulling from Convex: %w", err)
102→	}
103→
104→	result := &PullResult{
105→		PreviousVersion: previousVersion,
106→		CurrentVersion:  previousVersion,
107→		TableCounts:     make(map[string]int),
108→	}
109→	tablesUpdated := map[string]bool{}
110→
111→	for _, row := range resp.Rows {
112→		if err := e.upsertRow(row); err != nil {
113→			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
114→		}
115→		result.RowsUpserted++
116→		tablesUpdated[row.Table] = true
117→		result.TableCounts[row.Table]++
118→	}
119→	result.TablesUpdated = len(tablesUpdated)
120→
121→	if resp.SyncVersion > state.LastPullVersion {
122→		state.LastPullVersion = resp.SyncVersion
123→		result.CurrentVersion = resp.SyncVersion
124→		if err := e.saveSyncState(state); err != nil {
125→			return nil, fmt.Errorf("saving sync state: %w", err)
126→		}
127→	}
128→
129→	return result, nil
130→}
131→
132→// Push sends local state changes to Convex.
133→func (e *Engine) Push() (*PushResult, error) {
134→	state, err := e.loadSyncState()
135→	if err != nil {
136→		return nil, fmt.Errorf("loading sync state: %w", err)
137→	}
138→
139→	result := &PushResult{}
140→	var allRows []account.SyncRow
141→
142→	for _, table := range localTables {
143→		rows, err := e.changedLocalRows(table, state.LastPushAt)
144→		if err != nil {
145→			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
146→		}
147→		allRows = append(allRows, rows...)
148→		result.TablesScanned++
149→	}
150→
151→	// Also push email classifications (local authority for the classification field)
152→	classRows, err := e.changedEmailClassifications()
153→	if err != nil {
154→		return nil, fmt.Errorf("reading changed email classifications: %w", err)
155→	}
156→	allRows = append(allRows, classRows...)
157→
158→	if len(allRows) == 0 {
159→		return result, nil
160→	}
161→
162→	// Push in batches
163→	for i := 0; i < len(allRows); i += batchSize {
164→		end := i + batchSize
165→		if end > len(allRows) {
166→			end = len(allRows)
167→		}
168→		batch := allRows[i:end]
169→
170→		resp, err := e.client.PushLocalState(e.token, batch)
171→		if err != nil {
172→			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
173→		}
174→
175→		// Update local sync_version from server response
176→		for id, version := range resp.Versions {
177→			for _, row := range batch {
178→				if row.ID == id {
179→					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
180→						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
181→					}
182→					break
183→				}
184→			}
185→		}
186→		result.RowsPushed += len(batch)
187→	}
188→
189→	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
190→	if err := e.saveSyncState(state); err != nil {
191→		return nil, fmt.Errorf("saving sync state: %w", err)
192→	}
193→
194→	return result, nil
195→}
196→
197→// upsertRow writes a Convex row into the local SQLite table.
198→func (e *Engine) upsertRow(row account.SyncRow) error {
199→	if len(row.Data) == 0 {
200→		return nil
201→	}
202→
203→	columns := []string{"id"}
204→	placeholders := []string{"?"}
205→	values := []any{row.ID}
206→	updateParts := []string{}
207→
208→	for col, val := range row.Data {
209→		columns = append(columns, col)
210→		placeholders = append(placeholders, "?")
211→		values = append(values, val)
212→		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
213→	}
214→
215→	// Always set sync_version
216→	columns = append(columns, "sync_version")
217→	placeholders = append(placeholders, "?")
218→	values = append(values, row.Version)
219→	updateParts = append(updateParts, "sync_version = excluded.sync_version")
220→
221→	query := fmt.Sprintf(
222→		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
223→		row.Table,
224→		strings.Join(columns, ", "),
225→		strings.Join(placeholders, ", "),
226→		strings.Join(updateParts, ", "),
227→	)
228→
229→	_, err := e.db.Exec(query, values...)
230→	return err
231→}
232→
233→// changedLocalRows returns rows from a local-state table changed since lastPushAt.
234→func (e *Engine) changedLocalRows(table, lastPushAt string) ([]account.SyncRow, error) {
235→	var rows []account.SyncRow
236→
237→	query := fmt.Sprintf("SELECT * FROM %s", table)
238→	args := []any{}
239→	if lastPushAt != "" {
240→		query += " WHERE updated_at > ?"
241→		args = append(args, lastPushAt)
242→	}
243→
244→	sqlRows, err := e.db.Query(query, args...)
245→	if err != nil {
246→		return nil, err
247→	}
248→	defer sqlRows.Close()
249→
250→	cols, err := sqlRows.Columns()
251→	if err != nil {
252→		return nil, err
253→	}
254→
255→	for sqlRows.Next() {
256→		values := make([]any, len(cols))
257→		ptrs := make([]any, len(cols))
258→		for i := range values {
259→			ptrs[i] = &values[i]
260→		}
261→		if err := sqlRows.Scan(ptrs...); err != nil {
262→			return nil, err
263→		}
264→
265→		data := map[string]any{}
266→		var id string
267→		for i, col := range cols {
268→			if col == "id" {
269→				id = fmt.Sprintf("%v", values[i])
270→			}
271→			if col == "sync_version" {
272→				continue // don't push sync_version back
273→			}
274→			data[col] = values[i]
275→		}
276→
277→		rows = append(rows, account.SyncRow{
278→			Table: table,
279→			ID:    id,
280→			Data:  data,
281→		})
282→	}
283→
284→	return rows, sqlRows.Err()
285→}
286→
287→// changedEmailClassifications returns all classified emails for push.
288→// Emails lack updated_at so all are pushed each time — idempotent on Convex side.
289→func (e *Engine) changedEmailClassifications() ([]account.SyncRow, error) {
290→	sqlRows, err := e.db.Query(`SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`)
291→	if err != nil {
292→		return nil, err
293→	}
294→	defer sqlRows.Close()
295→
296→	var rows []account.SyncRow
297→	for sqlRows.Next() {
298→		var id, class, classifiedBy string
299→		var confidence float64
300→		if err := sqlRows.Scan(&id, &class, &confidence, &classifiedBy); err != nil {
301→			return nil, err
302→		}
303→
304→		rows = append(rows, account.SyncRow{
305→			Table: "emails",
306→			ID:    id,
307→			Data: map[string]any{
308→				"class":            class,
309→				"class_confidence": confidence,
310→				"classified_by":    classifiedBy,
311→			},
312→		})
313→	}
314→
315→	return rows, sqlRows.Err()
316→}
317→
318→// updateSyncVersion sets the sync_version for a specific row.
319→func (e *Engine) updateSyncVersion(table, id string, version int64) error {
320→	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
321→	_, err := e.db.Exec(query, version, id)
322→	return err
323→}
324→
325→const syncStateKey = "_sync_state"
326→
327→// loadSyncState reads the sync cursor from a local config-like store.
328→func (e *Engine) loadSyncState() (*SyncState, error) {
329→	// Store sync state in a simple key-value row in connectors table (reusing existing table)
330→	var data string
331→	err := e.db.QueryRow(
332→		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
333→	).Scan(&data)
334→	if err == sql.ErrNoRows {
335→		return &SyncState{}, nil
336→	}
337→	if err != nil {
338→		return nil, err
339→	}
340→
341→	var state SyncState
342→	if err := json.Unmarshal([]byte(data), &state); err != nil {
343→		return &SyncState{}, nil
344→	}
345→	return &state, nil
346→}
347→
348→// saveSyncState persists the sync cursor.
349→func (e *Engine) saveSyncState(state *SyncState) error {
350→	data, err := json.Marshal(state)
351→	if err != nil {
352→		return err
353→	}
354→
355→	_, err = e.db.Exec(`
356→		INSERT INTO connectors (id, type, sync_cursor)
357→		VALUES (?, 'sync', ?)
358→		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
359→		syncStateKey, string(data),
360→	)
361→	return err
362→}
